    hadoop_jar_step {
      jar  = format("s3://%s.elasticmapreduce/libs/script-runner/script-runner.jar", var.aws_region)
      args = [format("s3://%s/setup_jupyter.sh", aws_s3_bucket.sw_bucket.bucket), "${var.jupyter_name}"]
    }
  }

  configurations_json = <<EOF
  [
    {
