impacted_block_content:
data "vsphere_dynamic" "cluster_id" {
  filter                 = [data.vsphere_tag.zone_tag.id]
  type                   = "ClusterComputeResource"
  resolve_inventory_path = true
}

file_content:
# Copyright 2021 Flant JSC
# Licensed under the Deckhouse Platform Enterprise Edition (EE) license. See https://github.com/deckhouse/deckhouse/blob/main/ee/LICENSE

data "vsphere_tag_category" "region" {
  name = var.providerClusterConfiguration.regionTagCategory
}

data "vsphere_tag_category" "zone" {
  name = var.providerClusterConfiguration.zoneTagCategory
}

data "vsphere_tag" "region_tag" {
  name        = var.providerClusterConfiguration.region
  category_id = data.vsphere_tag_category.region.id
}

data "vsphere_dynamic" "datacenter_id" {
  filter                 = [data.vsphere_tag.region_tag.id]
  type                   = "Datacenter"
  resolve_inventory_path = true
}

data "vsphere_tag" "zone_tag" {
  name        = local.zone
  category_id = data.vsphere_tag_category.zone.id
}

data "vsphere_dynamic" "cluster_id" {
  filter                 = [data.vsphere_tag.zone_tag.id]
  type                   = "ClusterComputeResource"
  resolve_inventory_path = true
}

data "vsphere_datastore" "datastore" {
  name          = local.master_instance_class.datastore
  datacenter_id = data.vsphere_dynamic.datacenter_id.id
}

data "vsphere_resource_pool" "resource_pool" {
  count         = 1
  name          = join("/", [data.vsphere_dynamic.cluster_id.inventory_path, "Resources", local.resource_pool])
  datacenter_id = data.vsphere_dynamic.datacenter_id.id
}

data "vsphere_network" "main" {
  name          = replace(replace(local.master_instance_class.mainNetwork, "[", "\\["), "]", "\\]")
  datacenter_id = data.vsphere_dynamic.datacenter_id.id
}

data "vsphere_network" "internal" {
  for_each      = toset(local.additionalNetworks)
  name          = each.value
  datacenter_id = data.vsphere_dynamic.datacenter_id.id
}

data "vsphere_virtual_machine" "template" {
  name          = local.master_instance_class.template
  datacenter_id = data.vsphere_dynamic.datacenter_id.id
}

locals {
  external_addresss      = length(local.main_ip_addresses) > 0 ? element(local.main_ip_addresses, var.nodeIndex) : tomap({})
  external_ip            = lookup(local.external_addresss, "address", null)
  external_gateway       = lookup(local.external_addresss, "gateway", null)
  external_nameservers   = lookup(local.external_addresss, "nameservers", {})
  external_dns_addresses = lookup(local.external_nameservers, "addresses", null)
  external_dns_search    = lookup(local.external_nameservers, "search", null)

  main_interface_configuration = jsonencode(merge(
    local.external_ip == null ? { "dhcp4" = true } : tomap({}),
    local.external_ip != null ? { "addresses" = [local.external_ip] } : tomap({}),
    local.external_gateway != null ? { "gateway4" = local.external_gateway } : tomap({}),
    local.external_nameservers != {} ? {
      "nameservers" = merge(
        local.external_dns_addresses != null ? { "addresses" = local.external_dns_addresses } : tomap({}),
        local.external_dns_search != null ? { "search" = local.external_dns_search } : tomap({})
      )
    } : tomap({})
  ))

  internalNodeNetworkPrefix = try(split("/", var.providerClusterConfiguration.internalNetworkCIDR)[1], "")
  first_interface_index     = 192

  additional_interface_configurations = {
    for i, v in local.additionalNetworks :
    "ens${local.first_interface_index + 32 * (i + 1)}" =>
    { addresses = [join("", [cidrhost(var.providerClusterConfiguration.internalNetworkCIDR, var.nodeIndex + 10), "/", local.internalNodeNetworkPrefix])] }
  }

  cloud_init_network = {
    version = 2
    ethernets = merge({
      "ens${local.first_interface_index}" = jsondecode(local.main_interface_configuration)
    }, local.additional_interface_configurations)
  }

  cloud_init_metadata = {
    "local-hostname"   = join("-", [local.prefix, "master", var.nodeIndex])
    "public-keys-data" = var.providerClusterConfiguration.sshPublicKey
    "network"          = local.cloud_init_network
  }

  timesync_extra_conf = lookup(var.providerClusterConfiguration, "disableTimesync", true) ? {
    "time.synchronize.continue"      = "0"
    "time.synchronize.restore"       = "0"
    "time.synchronize.resume.disk"   = "FALSE"
    "time.synchronize.shrink"        = "0"
    "time.synchronize.tools.startup" = "FALSE"
    "time.synchronize.tools.enable"  = "FALSE"
    "time.synchronize.resume.host"   = "0"
  } : {}

  vm_extra_config_guestinfo = {
    "guestinfo.metadata"          = base64encode(jsonencode(local.cloud_init_metadata))
    "guestinfo.metadata.encoding" = "base64"
    "guestinfo.userdata"          = var.cloudConfig
    "guestinfo.userdata.encoding" = "base64"
  }

  vm_extra_config = merge(local.timesync_extra_conf, local.vm_extra_config_guestinfo)
}

resource "vsphere_virtual_disk" "kubernetes_data" {
  size               = 10
  datastore          = local.master_instance_class.datastore
  datacenter         = data.vsphere_dynamic.datacenter_id.inventory_path
  type               = "eagerZeroedThick"
  vmdk_path          = "deckhouse/${join("-", [var.clusterUUID, "kubernetes-data", var.nodeIndex])}.vmdk"
  create_directories = true
}

resource "vsphere_virtual_machine" "master" {
  name             = join("-", [local.prefix, "master", var.nodeIndex])
  resource_pool_id = data.vsphere_resource_pool.resource_pool[0].id
  datastore_id     = data.vsphere_datastore.datastore.id
  folder           = var.providerClusterConfiguration.vmFolderPath
  storage_policy_id = lookup(var.providerClusterConfiguration, "storagePolicyID", "")

  firmware = data.vsphere_virtual_machine.template.firmware
  num_cpus = local.master_instance_class.numCPUs
  memory   = local.master_instance_class.memory
  guest_id = data.vsphere_virtual_machine.template.guest_id

  scsi_type = data.vsphere_virtual_machine.template.scsi_type

  network_interface {
    network_id   = data.vsphere_network.main.id
    adapter_type = data.vsphere_virtual_machine.template.network_interface_types[0]
  }

  dynamic "network_interface" {
    for_each = local.additionalNetworks
    content {
      network_id   = data.vsphere_network.internal[network_interface.value].id
      adapter_type = data.vsphere_virtual_machine.template.network_interface_types[0]
    }
  }

  disk {
    label            = "disk0"
    unit_number      = 0
    size             = lookup(local.master_instance_class, "rootDiskSize", 50)
    eagerly_scrub    = false
    thin_provisioned = false
  }

  disk {
    label        = "disk1"
    unit_number  = 1
    attach       = true
    path         = vsphere_virtual_disk.kubernetes_data.vmdk_path
    datastore_id = data.vsphere_datastore.datastore.id
  }

  enable_disk_uuid = true

  nested_hv_enabled  = lookup(local.runtime_options, "nestedHardwareVirtualization", null)
  cpu_limit          = lookup(local.runtime_options, "cpuLimit", null)
  cpu_reservation    = lookup(local.runtime_options, "cpuReservation", null)
  cpu_share_count    = lookup(local.runtime_options, "cpuShares", null)
  memory_limit       = lookup(local.runtime_options, "memoryLimit", null)
  memory_reservation = lookup(local.runtime_options, "memoryReservation", null)
  memory_share_count = lookup(local.runtime_options, "memoryShares", null)

  extra_config = local.vm_extra_config

  clone {
    template_uuid = data.vsphere_virtual_machine.template.id
  }

  cdrom {
    client_device = true
  }

  depends_on = [vsphere_virtual_disk.kubernetes_data]

  lifecycle {
    ignore_changes = [
      extra_config,
      disk,
      vapp,
      firmware,
      ept_rvi_mode,
      hv_mode,
    ]
  }

  wait_for_guest_net_routable = false
}

impacted_block_content:
resource "aws_acm_certificate" "client_cert" {
  # Certificate needs to be US Virginia region in order to be used by cloudfront distribution
  provider          = aws.use1
  domain_name       = local.cert_domain_name[terraform.workspace]
  validation_method = "DNS"

  subject_alternative_names = local.cert_subject_alt_names[terraform.workspace]

  lifecycle {
    create_before_destroy = true
  }

  tags = merge(local.default_tags)
}

file_content:
################################################################################
# Client configurations

locals {
  client_s3_origin_id = "clientS3"

  cert_domain_name = {
    prod = local.app_domain
    dev  = local.app_domain2
    stg  = local.app_domain2
  }

  cert_subject_alt_names = {
    prod = sort(["*.${local.app_domain}", var.alias_domain[terraform.workspace]])
    dev  = sort(["*.${local.app_domain2}"])
    stg  = sort(["*.${local.app_domain2}"])
  }

  cloudfront_domain_aliases = {
    prod = [local.app_domain, var.alias_domain[terraform.workspace]]
    dev  = [local.app_domain2]
    stg  = [local.app_domain2]
  }
}

# S3 bucket storing client side (compiled) code
resource "aws_s3_bucket" "client_bucket" {
  bucket = "${local.org_name}-${local.stack_name_dash}-client-${terraform.workspace}"
  tags   = merge(local.default_tags)
}

resource "aws_s3_bucket_acl" "client_bucket" {
  bucket = aws_s3_bucket.client_bucket.id
  acl    = "private"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "client_bucket" {
  bucket = aws_s3_bucket.client_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_website_configuration" "client_bucket" {
  bucket = aws_s3_bucket.client_bucket.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "index.html"
  }
}

# Attach the policy to the client bucket
resource "aws_s3_bucket_policy" "client_bucket_policy" {
  bucket = aws_s3_bucket.client_bucket.id

  # Policy document for the client bucket
  policy = templatefile("policies/client_bucket_policy.json", {
    client_bucket_arn          = aws_s3_bucket.client_bucket.arn
    origin_access_identity_arn = aws_cloudfront_origin_access_identity.client_origin_access_identity.iam_arn
  })
}

# Origin access identity for cloudfront to access client s3 bucket
resource "aws_cloudfront_origin_access_identity" "client_origin_access_identity" {
  comment = "Origin access identity for client bucket"
}

# CloudFront response headers policy
resource "aws_cloudfront_response_headers_policy" "response_headers_policy" {
  # Based on SecurityHeadersPolicy
  # https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/using-managed-response-headers-policies.html

  name    = "SecurityHeadersPolicy-With-CSP"
  comment = "Based on AWS managed SecurityHeadersPolicy with CSP headers for Portal"

  security_headers_config {
    # HSTS
    # https://developer.mozilla.org/en-US/docs/Web/HTTP/Headers/Strict-Transport-Security
    strict_transport_security {
      override                   = true
      access_control_max_age_sec = 31536000
    }

    xss_protection {
      override   = true
      protection = true
      mode_block = true
    }

    content_type_options {
      override = true
    }

    referrer_policy {
      override        = true
      referrer_policy = "strict-origin-when-cross-origin"
    }

    frame_options {
      override     = true
      frame_option = "SAMEORIGIN"
    }

    ##
    # CSP
    # https://developer.mozilla.org/en-US/docs/Web/HTTP/CSP
    #
    # NOTES:
    # AWS Cloudfront accept policy statement in one (long) string format. Line breaks are not accepted.
    # If we can remove 'http://localhost:60151' then we could achieve maximum score A/A+.
    # Otherwise B+ with https://developer.mozilla.org/en-US/observatory
    content_security_policy {
      override                = true
      content_security_policy = "default-src 'none'; img-src https://*; child-src 'none'; frame-ancestors 'none'; base-uri 'self'; form-action 'self'; style-src 'self' 'unsafe-inline'; style-src-elem 'self' 'unsafe-inline'; font-src 'self'; script-src 'self' 'sha256-iyazmGim6+BpTEgzuYNeVGqbUJ+knl3GKSZKtwD/UH0='; connect-src https://api.unsplash.com https://*.ap-southeast-2.amazonaws.com https://*.auth.ap-southeast-2.amazoncognito.com https://*.s3.amazonaws.com https://s3.amazonaws.com https://api.portal.dev.umccr.org https://api.portal.stg.umccr.org https://api.portal.prod.umccr.org https://igv.org https://hgdownload.soe.ucsc.edu http://localhost:60151; frame-src 'self' https://*.s3.amazonaws.com https://s3.ap-southeast-2.amazonaws.com;"
    }
  }
}

# CloudFront layer for client S3 bucket access
resource "aws_cloudfront_distribution" "client_distribution" {
  origin {
    domain_name = aws_s3_bucket.client_bucket.bucket_regional_domain_name
    origin_id   = local.client_s3_origin_id

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.client_origin_access_identity.cloudfront_access_identity_path
    }
  }

  enabled             = true
  aliases             = local.cloudfront_domain_aliases[terraform.workspace]
  default_root_object = "index.html"

  viewer_certificate {
    acm_certificate_arn = aws_acm_certificate.client_cert.arn
    ssl_support_method  = "sni-only"
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = local.client_s3_origin_id

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 0
    max_ttl                = 0

    response_headers_policy_id = aws_cloudfront_response_headers_policy.response_headers_policy.id
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  # Route handling for SPA
  custom_error_response {
    error_caching_min_ttl = 0
    error_code            = 404
    response_code         = 200
    response_page_path    = "/index.html"
  }

  tags = merge(local.default_tags)
}

# Alias the client domain name to CloudFront distribution address
resource "aws_route53_record" "client_alias" {
  zone_id = data.aws_route53_zone.org_zone.zone_id
  name    = "${local.cert_domain_name[terraform.workspace]}."
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.client_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.client_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}

# Client certificate validation through a Route53 record
resource "aws_route53_record" "client_cert_validation" {
  for_each = {
  for dvo in aws_acm_certificate.client_cert.domain_validation_options : dvo.domain_name => {
    name   = dvo.resource_record_name
    record = dvo.resource_record_value
    type   = dvo.resource_record_type
  }
  }

  allow_overwrite = true
  name            = each.value.name
  records         = [each.value.record]
  type            = each.value.type
  ttl             = 60
  zone_id         = data.aws_route53_zone.org_zone.zone_id
}

# The certificate for client domain, validating using DNS
resource "aws_acm_certificate" "client_cert" {
  # Certificate needs to be US Virginia region in order to be used by cloudfront distribution
  provider          = aws.use1
  domain_name       = local.cert_domain_name[terraform.workspace]
  validation_method = "DNS"

  subject_alternative_names = local.cert_subject_alt_names[terraform.workspace]

  lifecycle {
    create_before_destroy = true
  }

  tags = merge(local.default_tags)
}

# Optional automatic certificate validation
# If count = 0, cert will be just created and pending validation
# Visit ACM Console UI and follow up to populate validation records in respective Route53 zones
# See var.certificate_validation note
resource "aws_acm_certificate_validation" "client_cert_dns" {
  count = var.certificate_validation[terraform.workspace]

  provider                = aws.use1
  certificate_arn         = aws_acm_certificate.client_cert.arn
  validation_record_fqdns = [for record in aws_route53_record.client_cert_validation : record.fqdn]

  depends_on = [aws_route53_record.client_cert_validation]
}

impacted_block_content:
resource "aws_ami_copy" "squid_ami" {
  count             = "${var.deploy_single_proxy ? 1 : 0 }"
  name              = "${var.env_vpc_name}-${data.aws_ami.public_squid_ami.name}-crypt"
  description       = "An encrypted copy of ${data.aws_ami.public_squid_ami.name}"
  source_ami_id     = "${data.aws_ami.public_squid_ami.id}"
  source_ami_region = "${var.ami_region}"
  encrypted         = true

  tags = {
    Name = "squid-${var.env_vpc_name}"
  }

  lifecycle {
    #
    # Do not force update when new ami becomes available.
    # We still need to improve our mechanism for tracking .ssh/authorized_keys
    # User can use 'terraform state taint' to trigger update.
    #
    ignore_changes = ["source_ami_id"]
  }
}

file_content:
# The squid proxy is the first thing that will start sending logs
# to the main loggroup, therefore we have to create it before the instance
# comes up. This group is also the main one for the rest of the entire common
#resource "aws_cloudwatch_log_group" "main_log_group" {
#  name              = "${var.env_vpc_name}"
#  retention_in_days = 1827
#
#  tags = {
#    Environment = "${var.env_vpc_name}"
#  }
#}

###############################################################
# IAM
###############################################################
resource "aws_iam_role" "cluster_logging_cloudwatch" {
  count = "${var.deploy_single_proxy ? 1 : 0 }"
  name  = "${var.env_vpc_name}_cluster_logging_cloudwatch"
  path  = "/"

  assume_role_policy = <<EOF
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Action": "sts:AssumeRole",
            "Principal": {
               "Service": "ec2.amazonaws.com"
            },
            "Effect": "Allow",
            "Sid": ""
        }
    ]
}
EOF
}

resource "aws_iam_role_policy" "cluster_logging_cloudwatch" {
  count  = "${var.deploy_single_proxy ? 1 : 0 }"
  name   = "${var.env_vpc_name}_cluster_logging_cloudwatch"
  policy = "${data.aws_iam_policy_document.cluster_logging_cloudwatch.json}"
  role   = "${aws_iam_role.cluster_logging_cloudwatch.id}"
}

resource "aws_iam_instance_profile" "cluster_logging_cloudwatch" {
  count  = "${var.deploy_single_proxy ? 1 : 0 }"
  name   = "${var.env_vpc_name}_cluster_logging_cloudwatch"
  role   = "${aws_iam_role.cluster_logging_cloudwatch.id}"
}



###############################################################
# AMI
###############################################################

# configure a dedicated aws provider for the region that contains
# the public source AMI. This allows the usage of other base regions.
provider "aws" {
  alias  = "ami-source-region"
  region = "${var.ami_region}"
}


resource "aws_ami_copy" "squid_ami" {
  count             = "${var.deploy_single_proxy ? 1 : 0 }"
  name              = "${var.env_vpc_name}-${data.aws_ami.public_squid_ami.name}-crypt"
  description       = "An encrypted copy of ${data.aws_ami.public_squid_ami.name}"
  source_ami_id     = "${data.aws_ami.public_squid_ami.id}"
  source_ami_region = "${var.ami_region}"
  encrypted         = true

  tags = {
    Name = "squid-${var.env_vpc_name}"
  }

  lifecycle {
    #
    # Do not force update when new ami becomes available.
    # We still need to improve our mechanism for tracking .ssh/authorized_keys
    # User can use 'terraform state taint' to trigger update.
    #
    ignore_changes = ["source_ami_id"]
  }
}

data "aws_ami" "public_squid_ami" {
  provider = "aws.ami-source-region"
  count       = "${var.deploy_single_proxy ? 1 : 0 }"
  most_recent = true

  filter {
    name   = "name"
    values = ["${var.ami_name}"]
  }

  owners = ["${var.ami_account_id}"]
}



###############################################################
# SEC GROUPS 
###############################################################
resource "aws_security_group" "login-ssh" {
  count       = "${var.deploy_single_proxy ? 1 : 0 }"
  name        = "${var.env_vpc_name}-squid-login-ssh"
  description = "security group that only enables ssh from VPC nodes and CSOC"
  vpc_id      = "${var.env_vpc_id}"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "TCP"
    cidr_blocks = ["${var.env_vpc_cidr}", "${var.csoc_cidr}"]
  }

  tags = {
    Environment  = "${var.env_vpc_name}"
    Organization = "${var.organization_name}"
  }

  lifecycle {
    ignore_changes = ["description"]
  }
}

resource "aws_security_group" "proxy" {
  count       = "${var.deploy_single_proxy ? 1 : 0 }"
  name        = "${var.env_vpc_name}-squid-proxy"
  description = "allow inbound tcp at 3128"
  vpc_id      = "${var.env_vpc_id}"

  ingress {
    from_port   = 0
    to_port     = 3128
    protocol    = "TCP"
    cidr_blocks = ["${var.env_vpc_cidr}"]
  }

  tags = {
    Environment  = "${var.env_vpc_name}"
    Organization = "${var.organization_name}"
  }
}

resource "aws_security_group" "out" {
  count       = "${var.deploy_single_proxy ? 1 : 0 }"
  name        = "${var.env_vpc_name}-squid-out"
  description = "security group that allow outbound traffics"
  vpc_id      = "${var.env_vpc_id}"

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Environment  = "${var.env_vpc_name}"
    Organization = "${var.organization_name}"
  }
}


###############################################################
# Route53 
###############################################################
resource "aws_route53_record" "squid" {
  count   = "${var.deploy_single_proxy ? 1 : 0 }"
  zone_id = "${var.zone_id}"
  name    = "cloud-proxy"
  type    = "A"
  ttl     = "300"
  records = ["${aws_instance.proxy.*.private_ip}"]
  lifecycle = {
    ignore_changes = ["records"]
  }
}

###############################################################
# EIP 
###############################################################
resource "aws_eip" "squid" {
  count = "${var.deploy_single_proxy ? 1 : 0 }"
  vpc   = true
}

resource "aws_eip_association" "squid_eip" {
  count         = "${var.deploy_single_proxy ? 1 : 0 }"
  instance_id   = "${aws_instance.proxy.id}"
  allocation_id = "${aws_eip.squid.id}"
}



###############################################################
# EC2 
###############################################################
resource "aws_instance" "proxy" {
  count                  = "${var.deploy_single_proxy ? 1 : 0 }"
  ami                    = "${aws_ami_copy.squid_ami.id}"
  subnet_id              = "${var.env_public_subnet_id}"
  instance_type          = "${var.instance_type}"
  monitoring             = true
  source_dest_check      = false
  key_name               = "${var.ssh_key_name}"
  vpc_security_group_ids = ["${aws_security_group.proxy.id}", "${aws_security_group.login-ssh.id}", "${aws_security_group.out.id}"]
#  iam_instance_profile   = "${var.env_instance_profile}" 
  iam_instance_profile   = "${aws_iam_instance_profile.cluster_logging_cloudwatch.name}"

  tags = {
    Name         = "${var.env_vpc_name} HTTP Proxy"
    Environment  = "${var.env_vpc_name}"
    Organization = "${var.organization_name}"
  }

  user_data = <<EOF
#!/bin/bash
echo '127.0.1.1 ${var.env_vpc_name}_squid_proxy' | sudo tee --append /etc/hosts
sudo hostnamectl set-hostname ${var.env_vpc_name}_squid_proxy

sed -i 's/SERVER/http_proxy-auth-{hostname}-{instance_id}/g' /var/awslogs/etc/awslogs.conf
sed -i 's/VPC/'${var.env_log_group}'/g' /var/awslogs/etc/awslogs.conf
cat >> /var/awslogs/etc/awslogs.conf <<EOM
[syslog]
datetime_format = %b %d %H:%M:%S
file = /var/log/syslog
log_stream_name = http_proxy-syslog-{hostname}-{instance_id}
time_zone = LOCAL
log_group_name = ${var.env_log_group}
[squid/access.log]
file = /var/log/squid/access.log*
log_stream_name = http_proxy-squid_access-{hostname}-{instance_id}
log_group_name = ${var.env_log_group}
EOM

chmod 755 /etc/init.d/awslogs
systemctl enable awslogs
systemctl restart awslogs
EOF

  lifecycle {
    ignore_changes = ["ami", "key_name"]
    create_before_destroy = true
  }
}

