resource "aws_codepipeline" "codepipeline_data2" {
  count    = local.create_data2[terraform.workspace]
  name     = "${local.stack_name_dash}-${local.data2}-${terraform.workspace}"
  role_arn = aws_iam_role.codepipeline_base_role.arn

  artifact_store {
    location = aws_s3_bucket.codepipeline_bucket.bucket
    type     = "S3"
  }

  stage {
    name = "Source"

    action {
      name             = "Source"
      category         = "Source"
      owner            = "AWS"
      provider         = "CodeStarSourceConnection"
      output_artifacts = ["SourceArtifact"]
      version          = "1"

      configuration = {
        ConnectionArn    = data.aws_ssm_parameter.codestar_github_arn.value
        FullRepositoryId = "${local.org_name}/${local.github_repo_client}"
        BranchName       = "main"  # NOTE: this is intended
      }
    }
  }

  stage {
    name = "Build"

    action {
      name            = "Build"
      category        = "Build"
      owner           = "AWS"
      provider        = "CodeBuild"
      input_artifacts = ["SourceArtifact"]
      version         = "1"

      configuration = {
        ProjectName = local.data2_codebuild_project_name
      }
    }
  }

  tags = merge(local.default_tags)
}

file_content:
################################################################################
# data2 Client configurations
#
# FIXME: Data Portal App Client for data2
#  currently using `portal.umccr.org` `portal.prod.umccr.org`
#  This is meant to be thrown away at some point around Q2 '23.
#  Only targeted for PROD.
#  See also `app_data_portal_data2.tf` from `cognito_aai` stack
#  https://umccr.slack.com/archives/CP356DDCH/p1666922554239469?thread_ts=1666786848.939379&cid=CP356DDCH
#

locals {
  create_data2 = {
    prod = 1
    dev  = 0
    stg  = 0
  }

  data2                     = "data2"
  data2_client_s3_origin_id = "data2clientS3"

  data2_cert_subject_alt_names = {
    prod = sort(["*.${local.app_domain2}", var.alias_domain2[terraform.workspace]])
    dev  = sort(["*.${local.app_domain2}"])
    stg  = sort(["*.${local.app_domain2}"])
  }

  data2_cloudfront_domain_aliases = {
    prod = [local.app_domain2, var.alias_domain2[terraform.workspace]]
    dev  = [local.app_domain2]
    stg  = [local.app_domain2]
  }

  data2_param_prefix = "/data_portal/client/data2"

  data2_codebuild_project_name = "${local.stack_name_dash}-${local.data2}-${terraform.workspace}"
}

# S3 bucket storing client side (compiled) code
resource "aws_s3_bucket" "data2_client" {
  count  = local.create_data2[terraform.workspace]
  bucket = "${local.org_name}-${local.stack_name_dash}-client-${local.data2}"
  tags   = merge(local.default_tags)
}

resource "aws_s3_bucket_acl" "data2_client" {
  count  = local.create_data2[terraform.workspace]
  bucket = aws_s3_bucket.data2_client[0].id
  acl    = "private"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "data2_client" {
  count  = local.create_data2[terraform.workspace]
  bucket = aws_s3_bucket.data2_client[0].id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_website_configuration" "data2_client" {
  count  = local.create_data2[terraform.workspace]
  bucket = aws_s3_bucket.data2_client[0].id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "index.html"
  }
}

# Attach the policy to the client bucket
resource "aws_s3_bucket_policy" "data2_client_bucket_policy" {
  count  = local.create_data2[terraform.workspace]
  bucket = aws_s3_bucket.data2_client[0].id

  # Policy document for the client bucket
  policy = templatefile("policies/client_bucket_policy.json", {
    client_bucket_arn          = aws_s3_bucket.data2_client[0].arn
    origin_access_identity_arn = aws_cloudfront_origin_access_identity.data2_client_origin_access_identity[0].iam_arn
  })
}

# Origin access identity for cloudfront to access client s3 bucket
resource "aws_cloudfront_origin_access_identity" "data2_client_origin_access_identity" {
  count   = local.create_data2[terraform.workspace]
  comment = "Origin access identity for data2 client bucket"
}

# CloudFront layer for client S3 bucket access
resource "aws_cloudfront_distribution" "data2_client_distribution" {
  count = local.create_data2[terraform.workspace]

  origin {
    domain_name = aws_s3_bucket.data2_client[0].bucket_regional_domain_name
    origin_id   = local.data2_client_s3_origin_id

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.data2_client_origin_access_identity[0].cloudfront_access_identity_path
    }
  }

  enabled             = true
  aliases             = local.data2_cloudfront_domain_aliases[terraform.workspace]
  default_root_object = "index.html"

  viewer_certificate {
    acm_certificate_arn = aws_acm_certificate.data2_client_cert[0].arn
    ssl_support_method  = "sni-only"
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = local.data2_client_s3_origin_id

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 0
    max_ttl                = 0

    response_headers_policy_id = aws_cloudfront_response_headers_policy.response_headers_policy.id
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  # Route handling for SPA
  custom_error_response {
    error_caching_min_ttl = 0
    error_code            = 404
    response_code         = 200
    response_page_path    = "/index.html"
  }

  tags = merge(local.default_tags)
}

# Alias the client domain name to CloudFront distribution address
resource "aws_route53_record" "data2_client_alias" {
  count   = local.create_data2[terraform.workspace]
  zone_id = data.aws_route53_zone.org_zone.zone_id
  name    = "${local.app_domain2}."
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.data2_client_distribution[0].domain_name
    zone_id                = aws_cloudfront_distribution.data2_client_distribution[0].hosted_zone_id
    evaluate_target_health = false
  }
}

# The certificate for client domain, validating using DNS
resource "aws_acm_certificate" "data2_client_cert" {
  count = local.create_data2[terraform.workspace]

  # Certificate needs to be US Virginia region in order to be used by cloudfront distribution
  provider    = aws.use1
  domain_name = local.app_domain2

  # FIXME: Visit ACM Console UI and follow up to populate validation records in respective Route53 zones
  #  See var.certificate_validation note
  validation_method = "DNS"

  subject_alternative_names = local.data2_cert_subject_alt_names[terraform.workspace]

  lifecycle {
    create_before_destroy = true
  }

  tags = merge(local.default_tags)
}


################################################################################
# Deployment pipeline configurations

# Codepipeline for data2 client
resource "aws_codepipeline" "codepipeline_data2" {
  count    = local.create_data2[terraform.workspace]
  name     = "${local.stack_name_dash}-${local.data2}-${terraform.workspace}"
  role_arn = aws_iam_role.codepipeline_base_role.arn

  artifact_store {
    location = aws_s3_bucket.codepipeline_bucket.bucket
    type     = "S3"
  }

  stage {
    name = "Source"

    action {
      name             = "Source"
      category         = "Source"
      owner            = "AWS"
      provider         = "CodeStarSourceConnection"
      output_artifacts = ["SourceArtifact"]
      version          = "1"

      configuration = {
        ConnectionArn    = data.aws_ssm_parameter.codestar_github_arn.value
        FullRepositoryId = "${local.org_name}/${local.github_repo_client}"
        BranchName       = "main"  # NOTE: this is intended
      }
    }
  }

  stage {
    name = "Build"

    action {
      name            = "Build"
      category        = "Build"
      owner           = "AWS"
      provider        = "CodeBuild"
      input_artifacts = ["SourceArtifact"]
      version         = "1"

      configuration = {
        ProjectName = local.data2_codebuild_project_name
      }
    }
  }

  tags = merge(local.default_tags)
}

data "aws_ssm_parameter" "data2_cog_app_client_id_stage" {
  count = local.create_data2[terraform.workspace]
  name  = "${local.data2_param_prefix}/cog_app_client_id_stage"
}

data "aws_ssm_parameter" "data2_oauth_redirect_in_stage" {
  count = local.create_data2[terraform.workspace]
  name  = "${local.data2_param_prefix}/oauth_redirect_in_stage"
}

data "aws_ssm_parameter" "data2_oauth_redirect_out_stage" {
  count = local.create_data2[terraform.workspace]
  name  = "${local.data2_param_prefix}/oauth_redirect_out_stage"
}

# Codebuild project for client
resource "aws_codebuild_project" "codebuild_data2" {
  count        = local.create_data2[terraform.workspace]
  name         = local.data2_codebuild_project_name
  service_role = aws_iam_role.codebuild_client_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/amazonlinux-aarch64-standard:3.0"
    type         = "ARM_CONTAINER"

    environment_variable {
      name  = "STAGE"
      value = terraform.workspace
    }

    environment_variable {
      name  = "S3"
      value = "s3://${aws_s3_bucket.data2_client[0].bucket}"  # NOTE: pointing to data2 bucket
    }

    environment_variable {
      name  = "API_URL"
      # FIXME: https://github.com/umccr/infrastructure/issues/272
      # value = local.api_domain
      value = local.api_domain2
    }

    environment_variable {
      name  = "HTSGET_URL"
      value = data.aws_ssm_parameter.htsget_domain.value
    }

    environment_variable {
      name  = "REGION"
      value = data.aws_region.current.name
    }

    environment_variable {
      name  = "COGNITO_USER_POOL_ID"
      value = data.aws_ssm_parameter.cog_user_pool_id.value
    }

    environment_variable {
      name  = "COGNITO_IDENTITY_POOL_ID"
      value = data.aws_ssm_parameter.cog_identity_pool_id.value
    }

    environment_variable {
      name  = "COGNITO_APP_CLIENT_ID_STAGE"
      value = data.aws_ssm_parameter.data2_cog_app_client_id_stage[0].value
    }

    environment_variable {
      name  = "OAUTH_DOMAIN"
      value = data.aws_ssm_parameter.oauth_domain.value
    }

    environment_variable {
      name  = "OAUTH_REDIRECT_IN_STAGE"
      value = data.aws_ssm_parameter.data2_oauth_redirect_in_stage[0].value
    }

    environment_variable {
      name  = "OAUTH_REDIRECT_OUT_STAGE"
      value = data.aws_ssm_parameter.data2_oauth_redirect_out_stage[0].value
    }

    environment_variable {
      name  = "UNSPLASH_CLIENT_ID"
      value = data.aws_ssm_parameter.unsplash_client_id.value
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/${local.org_name}/${local.github_repo_client}.git"
    git_clone_depth = 1
  }

  tags = merge(local.default_tags)
}

resource "aws_codestarnotifications_notification_rule" "data2_build_status" {
  count       = local.create_data2[terraform.workspace]
  name        = "${local.stack_name_us}_${local.data2}_code_build_status"
  resource    = aws_codebuild_project.codebuild_data2[0].arn
  detail_type = "BASIC"

  target {
    address = local.notification_sns_topic_arn[terraform.workspace]
  }

  event_type_ids = [
    "codebuild-project-build-state-failed",
    "codebuild-project-build-state-succeeded",
  ]

  tags = merge(local.default_tags)
}

impacted_block_content:
resource "aws_codestarnotifications_notification_rule" "apis_build_status" {
  name        = "${local.stack_name_us}_apis_code_build_status"
  resource    = aws_codebuild_project.codebuild_apis.arn
  detail_type = "BASIC"

  target {
    address = local.notification_sns_topic_arn[terraform.workspace]
  }

  event_type_ids = [
    "codebuild-project-build-state-failed",
    "codebuild-project-build-state-succeeded",
  ]

  tags = merge(local.default_tags)
}

file_content:
################################################################################
# Deployment pipeline configurations

locals {
  github_repo_client = "data-portal-client"
  github_repo_apis   = "data-portal-apis"

  codebuild_project_name_client = "data-portal-client-${terraform.workspace}"
  codebuild_project_name_apis   = "data-portal-apis-${terraform.workspace}"

  # FIXME: remove this when resolve https://github.com/umccr/infrastructure/issues/272
  cog_client_id_by_env = {
    prod = data.aws_ssm_parameter.cog_app_client_id_stage.value
    dev  = data.aws_ssm_parameter.tmp_cog_app_client_id_stage.value
    stg  = data.aws_ssm_parameter.tmp_cog_app_client_id_stage.value
  }
  # FIXME: remove this when resolve https://github.com/umccr/infrastructure/issues/272
  cog_redirect_in_by_env = {
    prod = data.aws_ssm_parameter.oauth_redirect_in_stage.value
    dev  = data.aws_ssm_parameter.tmp_oauth_redirect_in_stage.value
    stg  = data.aws_ssm_parameter.tmp_oauth_redirect_in_stage.value
  }
  # FIXME: remove this when resolve https://github.com/umccr/infrastructure/issues/272
  cog_redirect_out_by_env = {
    prod = data.aws_ssm_parameter.oauth_redirect_out_stage.value
    dev  = data.aws_ssm_parameter.tmp_oauth_redirect_out_stage.value
    stg  = data.aws_ssm_parameter.tmp_oauth_redirect_out_stage.value
  }
}

# FIXME: remove this when resolve https://github.com/umccr/infrastructure/issues/272
data "aws_ssm_parameter" "tmp_cog_app_client_id_stage" {
  name  = "${local.data2_param_prefix}/cog_app_client_id_stage"
}

# FIXME: remove this when resolve https://github.com/umccr/infrastructure/issues/272
data "aws_ssm_parameter" "tmp_oauth_redirect_in_stage" {
  name  = "${local.data2_param_prefix}/oauth_redirect_in_stage"
}

# FIXME: remove this when resolve https://github.com/umccr/infrastructure/issues/272
data "aws_ssm_parameter" "tmp_oauth_redirect_out_stage" {
  name  = "${local.data2_param_prefix}/oauth_redirect_out_stage"
}

data "aws_ssm_parameter" "codestar_github_arn" {
  name = "codestar_github_arn"
}

data "aws_ssm_parameter" "unsplash_client_id" {
  name = "/${local.stack_name_us}/unsplash/client_id"
}

data "aws_ssm_parameter" "cog_user_pool_id" {
  name = "${local.ssm_param_key_client_prefix}/cog_user_pool_id"
}

data "aws_ssm_parameter" "cog_identity_pool_id" {
  name = "${local.ssm_param_key_client_prefix}/cog_identity_pool_id"
}

data "aws_ssm_parameter" "oauth_domain" {
  name = "${local.ssm_param_key_client_prefix}/oauth_domain"
}

data "aws_ssm_parameter" "cog_app_client_id_stage" {
  name = "${local.ssm_param_key_client_prefix}/cog_app_client_id_stage"
}

data "aws_ssm_parameter" "oauth_redirect_in_stage" {
  name = "${local.ssm_param_key_client_prefix}/oauth_redirect_in_stage"
}

data "aws_ssm_parameter" "oauth_redirect_out_stage" {
  name = "${local.ssm_param_key_client_prefix}/oauth_redirect_out_stage"
}

data "aws_ssm_parameter" "htsget_domain" {
  name = "/htsget/domain"
}

# Bucket storing codepipeline artifacts (both client and apis)
resource "aws_s3_bucket" "codepipeline_bucket" {
  bucket = "${local.org_name}-${local.stack_name_dash}-build-${terraform.workspace}"
  tags   = merge(local.default_tags)
}

resource "aws_s3_bucket_acl" "codepipeline_bucket" {
  bucket = aws_s3_bucket.codepipeline_bucket.id
  acl    = "private"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "codepipeline_bucket" {
  bucket = aws_s3_bucket.codepipeline_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_iam_role" "codepipeline_base_role" {
  name = "${local.stack_name_us}_codepipeline_base_role"
  path = local.iam_role_path

  # Base IAM role for codepipeline service
  assume_role_policy = templatefile("policies/codepipeline_base_role_assume_role_policy.json", {})

  tags = merge(local.default_tags)
}

resource "aws_iam_role_policy" "codepipeline_base_role_policy" {
  name = "${local.stack_name_us}_codepipeline_base_role_policy"
  role = aws_iam_role.codepipeline_base_role.id

  # Base IAM policy for codepiepline service role
  policy = templatefile("policies/codepipeline_base_role_policy.json", {
    codepipeline_bucket_arn              = aws_s3_bucket.codepipeline_bucket.arn
    codepipeline_codestar_connection_arn = data.aws_ssm_parameter.codestar_github_arn.value
  })
}

# Codepipeline for client
resource "aws_codepipeline" "codepipeline_client" {
  name     = "${local.stack_name_dash}-client-${terraform.workspace}"
  role_arn = aws_iam_role.codepipeline_base_role.arn

  artifact_store {
    location = aws_s3_bucket.codepipeline_bucket.bucket
    type     = "S3"
  }

  stage {
    name = "Source"

    action {
      name             = "Source"
      category         = "Source"
      owner            = "AWS"
      provider         = "CodeStarSourceConnection"
      output_artifacts = ["SourceArtifact"]
      version          = "1"

      configuration = {
        ConnectionArn    = data.aws_ssm_parameter.codestar_github_arn.value
        FullRepositoryId = "${local.org_name}/${local.github_repo_client}"
        BranchName       = var.github_branch_frontend[terraform.workspace]
      }
    }
  }

  stage {
    name = "Build"

    action {
      name            = "Build"
      category        = "Build"
      owner           = "AWS"
      provider        = "CodeBuild"
      input_artifacts = ["SourceArtifact"]
      version         = "1"

      configuration = {
        ProjectName = local.codebuild_project_name_client
      }
    }
  }

  tags = merge(local.default_tags)
}

# Codepipeline for apis
resource "aws_codepipeline" "codepipeline_apis" {
  name     = "${local.stack_name_dash}-apis-${terraform.workspace}"
  role_arn = aws_iam_role.codepipeline_base_role.arn

  artifact_store {
    location = aws_s3_bucket.codepipeline_bucket.bucket
    type     = "S3"
  }

  stage {
    name = "Source"

    action {
      name             = "Source"
      category         = "Source"
      owner            = "AWS"
      provider         = "CodeStarSourceConnection"
      output_artifacts = ["SourceArtifact"]
      version          = "1"

      configuration = {
        ConnectionArn    = data.aws_ssm_parameter.codestar_github_arn.value
        FullRepositoryId = "${local.org_name}/${local.github_repo_apis}"
        BranchName       = var.github_branch_backend[terraform.workspace]
      }
    }
  }

  stage {
    name = "Build"

    action {
      name            = "Build"
      category        = "Build"
      owner           = "AWS"
      provider        = "CodeBuild"
      input_artifacts = ["SourceArtifact"]
      version         = "1"

      configuration = {
        ProjectName = local.codebuild_project_name_apis
      }
    }
  }

  tags = merge(local.default_tags)
}

resource "aws_iam_role" "codebuild_client_role" {
  name = "${local.stack_name_us}_codebuild_client_service_role"
  path = local.iam_role_path

  # IAM role for code build (client)
  assume_role_policy = templatefile("policies/codebuild_client_role_assume_role_policy.json", {})

  tags = merge(local.default_tags)
}

resource "aws_iam_role" "codebuild_apis_role" {
  name = "${local.stack_name_us}_codebuild_apis_service_role"
  path = local.iam_role_path

  # IAM role for code build (api)
  assume_role_policy = templatefile("policies/codebuild_apis_role_assume_role_policy.json", {})

  tags = merge(local.default_tags)
}

resource "aws_iam_policy" "codebuild_apis_policy" {
  name        = "${local.stack_name_us}_codebuild_apis_service_policy"
  description = "Policy for CodeBuild for backend side of data portal"

  # IAM policy specific for the apis side
  policy = templatefile("policies/codebuild_apis_policy.json", {
    subnet_id0 = sort(data.aws_subnets.private_subnets_ids.ids)[0],
    subnet_id1 = sort(data.aws_subnets.private_subnets_ids.ids)[1],
    subnet_id2 = sort(data.aws_subnets.private_subnets_ids.ids)[2],

    region     = data.aws_region.current.name,
    account_id = data.aws_caller_identity.current.account_id
  })
}

# Attach the base policy to the code build role for client
resource "aws_iam_role_policy_attachment" "codebuild_client_role_attach_base_policy" {
  role       = aws_iam_role.codebuild_client_role.name
  policy_arn = aws_iam_policy.codebuild_base_policy.arn
}

# Attach the base policy to the code build role for apis
resource "aws_iam_role_policy_attachment" "codebuild_apis_role_attach_base_policy" {
  role       = aws_iam_role.codebuild_apis_role.name
  policy_arn = aws_iam_policy.codebuild_base_policy.arn
}

# Attach specific policies to the code build ro for apis
resource "aws_iam_role_policy_attachment" "codebuild_apis_role_attach_specific_policy" {
  role       = aws_iam_role.codebuild_apis_role.name
  policy_arn = aws_iam_policy.codebuild_apis_policy.arn
}

resource "aws_iam_policy" "codebuild_base_policy" {
  name        = "codebuild-${local.stack_name_dash}-base-service-policy"
  description = "Base policy for CodeBuild for data portal site"

  # Base IAM policy for code build
  policy = templatefile("policies/codebuild_base_policy.json", {})
}

# Codebuild project for client
resource "aws_codebuild_project" "codebuild_client" {
  name         = local.codebuild_project_name_client
  service_role = aws_iam_role.codebuild_client_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/amazonlinux-aarch64-standard:3.0"
    type         = "ARM_CONTAINER"

    environment_variable {
      name  = "STAGE"
      value = terraform.workspace
    }

    environment_variable {
      name  = "S3"
      value = "s3://${aws_s3_bucket.client_bucket.bucket}"
    }

    environment_variable {
      name  = "API_URL"
      value = local.api_domain_by_env[terraform.workspace]
    }

    environment_variable {
      name  = "HTSGET_URL"
      value = data.aws_ssm_parameter.htsget_domain.value
    }

    environment_variable {
      name  = "REGION"
      value = data.aws_region.current.name
    }

    environment_variable {
      name  = "COGNITO_USER_POOL_ID"
      value = data.aws_ssm_parameter.cog_user_pool_id.value
    }

    environment_variable {
      name  = "COGNITO_IDENTITY_POOL_ID"
      value = data.aws_ssm_parameter.cog_identity_pool_id.value
    }

    environment_variable {
      name  = "COGNITO_APP_CLIENT_ID_STAGE"
      value = local.cog_client_id_by_env[terraform.workspace]
    }

    environment_variable {
      name  = "OAUTH_DOMAIN"
      value = data.aws_ssm_parameter.oauth_domain.value
    }

    environment_variable {
      name  = "OAUTH_REDIRECT_IN_STAGE"
      value = local.cog_redirect_in_by_env[terraform.workspace]
    }

    environment_variable {
      name  = "OAUTH_REDIRECT_OUT_STAGE"
      value = local.cog_redirect_out_by_env[terraform.workspace]
    }

    environment_variable {
      name  = "UNSPLASH_CLIENT_ID"
      value = data.aws_ssm_parameter.unsplash_client_id.value
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/${local.org_name}/${local.github_repo_client}.git"
    git_clone_depth = 1
  }

  tags = merge(local.default_tags)
}

# Codebuild project for apis
resource "aws_codebuild_project" "codebuild_apis" {
  name         = local.codebuild_project_name_apis
  service_role = aws_iam_role.codebuild_apis_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux-aarch64-standard:3.0"
    type            = "ARM_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "STAGE"
      value = terraform.workspace
    }

    environment_variable {
      name  = "ICA_BASE_URL"      # this is used only within CodeBuild dind scope
      value = "http://localhost"
    }

    environment_variable {
      name  = "ICA_ACCESS_TOKEN"
      value = "any_value_work"  # this is used only within CodeBuild dind Prism mock stack for build test purpose only
    }
  }

  /* UNCOMMENT TO ADD VPC SUPPORT FOR CODEBUILD
  vpc_config {
    vpc_id = data.aws_vpc.main_vpc.id
    subnets = data.aws_subnet_ids.private_subnets_ids.ids
    security_group_ids = [
      aws_security_group.codebuild_apis_security_group.id,
    ]
  }
  */

  source {
    type            = "GITHUB"
    location        = "https://github.com/${local.org_name}/${local.github_repo_apis}.git"
    git_clone_depth = 1
  }

  tags = merge(local.default_tags)
}

################################################################################
# Notification: CodeBuild build status send through SNS topic to ChatBot to
# Slack channel #alerts-build for all CodeBuild environments

data "aws_sns_topic" "alerts_build_topic" {
  name = "AwsChatBotTopic-alerts-build"
}

locals {
  notification_sns_topic_arn = {
    prod = data.aws_sns_topic.alerts_build_topic.arn
    dev  = data.aws_sns_topic.alerts_build_topic.arn
    stg  = data.aws_sns_topic.alerts_build_topic.arn
  }
}

resource "aws_codestarnotifications_notification_rule" "apis_build_status" {
  name        = "${local.stack_name_us}_apis_code_build_status"
  resource    = aws_codebuild_project.codebuild_apis.arn
  detail_type = "BASIC"

  target {
    address = local.notification_sns_topic_arn[terraform.workspace]
  }

  event_type_ids = [
    "codebuild-project-build-state-failed",
    "codebuild-project-build-state-succeeded",
  ]

  tags = merge(local.default_tags)
}

resource "aws_codestarnotifications_notification_rule" "client_build_status" {
  name        = "${local.stack_name_us}_client_code_build_status"
  resource    = aws_codebuild_project.codebuild_client.arn
  detail_type = "BASIC"

  target {
    address = local.notification_sns_topic_arn[terraform.workspace]
  }

  event_type_ids = [
    "codebuild-project-build-state-failed",
    "codebuild-project-build-state-succeeded",
  ]

  tags = merge(local.default_tags)
}

resource "aws_ssm_parameter" "notification_sns_topic_arn" {
  name  = "${local.ssm_param_key_backend_prefix}/notification_sns_topic_arn"
  type  = "String"
  value = local.notification_sns_topic_arn[terraform.workspace]
  tags  = merge(local.default_tags)
}

impacted_block_content:
resource "aws_config_aggregate_authorization" "named_test_resource" {
  account_id = "123456789012"
  region     = "eu-west-2"
  tags = {
    name = var.resource_name
  }
}

file_content:
variable "resource_name" {
  type        = string
  default     = "turbot-test-20200125-create-update"
  description = "Name of the resource used throughout the test."
}

variable "aws_profile" {
  type        = string
  default     = "default"
  description = "AWS credentials profile used for the test. Default is to use the default profile."
}

variable "aws_region" {
  type        = string
  default     = "us-east-1"
  description = "AWS region used for the test. Does not work with default region in config, so must be defined here."
}

variable "aws_region_alternate" {
  type        = string
  default     = "us-east-2"
  description = "Alternate AWS region used for tests that require two regions (e.g. DynamoDB global tables)."
}

provider "aws" {
  profile = var.aws_profile
  region  = var.aws_region
}

provider "aws" {
  alias   = "alternate"
  profile = var.aws_profile
  region  = var.aws_region_alternate
}

data "aws_partition" "current" {}
data "aws_caller_identity" "current" {}
data "aws_region" "primary" {}
data "aws_region" "alternate" {
  provider = aws.alternate
}

data "null_data_source" "resource" {
  inputs = {
    scope = "arn:${data.aws_partition.current.partition}:::${data.aws_caller_identity.current.account_id}"
  }
}

# Create AWS > Config > Rule
resource "aws_config_aggregate_authorization" "named_test_resource" {
  account_id = "123456789012"
  region     = "eu-west-2"
  tags = {
    name = var.resource_name
  }
}

output "account_id" {
  value = data.aws_caller_identity.current.account_id
}

output "region_name" {
  value = data.aws_region.primary.name
}

output "authorized_account_id" {
  value = split( "/", aws_config_aggregate_authorization.named_test_resource.arn)[1]
}

output "authorized_aws_region" {
  value = split( "/", aws_config_aggregate_authorization.named_test_resource.arn)[2]
}

output "aws_partition" {
  value = data.aws_partition.current.partition
}

output "resource_name" {
  value = var.resource_name
}

output "resource_aka" {
  value = aws_config_aggregate_authorization.named_test_resource.arn
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.54.0, < 5.0.0" # 4.54.0 at least is required for proper AWS SSO support, see #626
    }
  }
}
provider "aws" {
  skip_region_validation      = true
  skip_credentials_validation = true
  skip_get_ec2_platforms      = true
  default_tags {
    tags = {
      StratusRedTeam = true
    }
  }
}

resource "random_password" "password" {
  length    = 32
  min_lower = 32
  special   = false
}

locals {
  resource_prefix = "stratus-red-team-share-snap"
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 3.0"

  name = "${local.resource_prefix}-vpc"
  cidr = "10.0.0.0/16"

  azs              = [data.aws_availability_zones.available.names[0], data.aws_availability_zones.available.names[1]]
  database_subnets = ["10.0.1.0/24", "10.0.2.0/24"]

  map_public_ip_on_launch = false
  enable_nat_gateway      = false

  tags = {
    StratusRedTeam = true
  }
}

resource "aws_db_instance" "default" {
  allocated_storage       = 10 // minimum size
  engine                  = "mysql"
  engine_version          = "8.0"
  instance_class          = "db.t3.micro"
  name                    = "${replace(local.resource_prefix, "-", "")}db"
  backup_retention_period = 0
  db_subnet_group_name    = module.vpc.database_subnet_group_name
  username                = "admin"
  password                = random_password.password.result
  skip_final_snapshot     = true
  apply_immediately       = true
}

resource "aws_db_snapshot" "snapshot" {
  db_instance_identifier = aws_db_instance.default.id
  db_snapshot_identifier = "exfiltration"
}

output "rds_instance_id" {
  value = aws_db_instance.default.id
}

output "snapshot_id" {
  value = aws_db_snapshot.snapshot.id
}

output "display" {
  value = format("RDS Snapshot %s of RDS Instance %s is ready", aws_db_snapshot.snapshot.id, aws_db_instance.default.id)
}

# Specify the provider and access details
provider "aws" {
  region = "${var.aws_region}"
}

#module "postgres" {
#    source = "./postgres"
#    access_allowed_security_groups = "${aws_security_group.atc.id}"
#}

module "autoscaling_hooks" {
    source = "./autoscaling/hooks/enabled"
    target_asg_name = "${aws_autoscaling_group.worker-asg.name}"
    prefix = "${var.prefix}"
}

module "autoscaling_schedule" {
    source = "./autoscaling/schedule/enabled"
    target_asg_name = "${aws_autoscaling_group.worker-asg.name}"
    num_workers_during_working_time = 2
    max_num_workers_during_working_time = "${var.asg_max}"
    num_workers_during_non_working_time = 0
}

module "autoscaling_utilization" {
    source = "./autoscaling/utilization/enabled"
    target_asg_name = "${aws_autoscaling_group.worker-asg.name}"
}

resource "aws_elb" "web-elb" {
  name = "${var.prefix}concourse-lb"

  # The same availability zone as our instances
  # Only one of SubnetIds or AvailabilityZones may be specified
  #availability_zones = ["${split(",", var.availability_zones)}"]
  security_groups = ["${aws_security_group.external_lb.id}"]
  subnets = ["${split(",", var.subnet_id)}"]
  cross_zone_load_balancing = "true"

  listener {
    instance_port = "${var.elb_listener_instance_port}"
    instance_protocol = "http"
    lb_port = "${var.elb_listener_lb_port}"
    lb_protocol = "${var.elb_listener_lb_protocol}"
    ssl_certificate_id = "${var.ssl_certificate_arn}"
  }

  listener {
    instance_port = "${var.tsa_port}"
    instance_protocol = "tcp"
    lb_port = "${var.tsa_port}"
    lb_protocol = "tcp"
  }

  health_check {
    healthy_threshold = 2
    unhealthy_threshold = 2
    timeout = 3
    target = "TCP:${var.elb_listener_instance_port}"
    interval = 30
  }
}

resource "aws_autoscaling_group" "web-asg" {
  # See "Phasing in" an Autoscaling Group? https://groups.google.com/forum/#!msg/terraform-tool/7Gdhv1OAc80/iNQ93riiLwAJ
  # * Recreation of the launch configuration triggers recreation of this ASG and its EC2 instances
  # * Modification to the lc (change to referring AMI) triggers recreation of this ASG
  name = "${var.prefix}${aws_launch_configuration.web-lc.name}${var.ami}"
  availability_zones = ["${split(",", var.availability_zones)}"]
  max_size = "${var.asg_max}"
  min_size = "${var.asg_min}"
  desired_capacity = "${var.web_asg_desired}"
  launch_configuration = "${aws_launch_configuration.web-lc.name}"
  load_balancers = ["${aws_elb.web-elb.name}"]
  vpc_zone_identifier = ["${split(",", var.subnet_id)}"]
  tag {
    key = "Name"
    value = "${var.prefix}web"
    propagate_at_launch = "true"
  }
  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_autoscaling_group" "worker-asg" {
  name = "${var.prefix}${aws_launch_configuration.worker-lc.name}${var.ami}"
  availability_zones = ["${split(",", var.availability_zones)}"]
  max_size = "${var.asg_max}"
  min_size = "${var.asg_min}"
  desired_capacity = "${var.worker_asg_desired}"
  launch_configuration = "${aws_launch_configuration.worker-lc.name}"
  vpc_zone_identifier = ["${split(",", var.subnet_id)}"]
  tag {
    key = "Name"
    value = "${var.prefix}worker"
    propagate_at_launch = "true"
  }
  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_launch_configuration" "web-lc" {
  # Omit launch configuration name to avoid collisions on create_before_destroy
  # ref. https://github.com/hashicorp/terraform/issues/1109#issuecomment-97970885
  #image_id = "${lookup(var.aws_amis, var.aws_region)}"
  image_id = "${var.ami}"
  instance_type = "${var.web_instance_type}"
  security_groups = ["${aws_security_group.default.id}","${aws_security_group.atc.id}","${aws_security_group.tsa.id}"]
  user_data = "${template_cloudinit_config.web.rendered}"
  key_name = "${var.key_name}"
  associate_public_ip_address = true
  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_launch_configuration" "worker-lc" {
  #image_id = "${lookup(var.aws_amis, var.aws_region)}"
  image_id = "${var.ami}"
  instance_type = "${var.worker_instance_type}"
  security_groups = ["${aws_security_group.default.id}", "${aws_security_group.worker.id}"]
  user_data = "${template_cloudinit_config.worker.rendered}"
  key_name = "${var.key_name}"
  associate_public_ip_address = true
  iam_instance_profile = "${var.worker_instance_profile}"
  root_block_device {
    # For fast booting, we use gp2
    volume_type = "gp2"
    # You need enough capacity to avoid the following error while docker export & untar'ing:
    #
    # *snip*
    # tar: etc/alternatives: Cannot stat: Input/output error
    # tar: etc: Cannot stat: Input/output error
    # tar: dev: Cannot stat: Input/output error
    # tar: bin: Cannot stat: Input/output error
    # tar: Exiting with failure status due to previous errors
    #
    # resource script '/opt/resource/in [/tmp/build/get]' failed: exit status 2
    #
    # Or the following error when tried to run the job:
    # resource_pool: creating container directory: mkdir /var/lib/concourse/linux/depot/hntrh2no0mh: no space left on device
    volume_size = "50"
    delete_on_termination = true
  }
  lifecycle {
    create_before_destroy = true
  }
}

resource "template_file" "install_concourse" {
  template = "${file("${path.module}/00_install_concourse.sh.tpl")}"
}

resource "template_file" "start_concourse_web" {
  template = "${file("${path.module}/01_start_concourse_web.sh.tpl")}"

  vars {
    session_signing_key = "${file("${var.session_signing_key}")}"
    tsa_host_key = "${file("${var.tsa_host_key}")}"
    tsa_authorized_keys = "${file("${var.tsa_authorized_keys}")}"
    postgres_data_source = "postgres://${var.db_username}:${var.db_password}@${aws_db_instance.default.endpoint}/concourse"
    external_url = "${var.elb_listener_lb_protocol}://${element(split(",","${aws_elb.web-elb.dns_name},${var.custom_external_domain_name}"), var.use_custom_external_domain_name)}${element(split(",",",:${var.elb_listener_lb_port}"), var.use_custom_elb_port)}"
    basic_auth_username = "${var.basic_auth_username}"
    basic_auth_password = "${var.basic_auth_password}"
    github_auth_client_id = "${var.github_auth_client_id}"
    github_auth_client_secret = "${var.github_auth_client_secret}"
    github_auth_organizations = "${var.github_auth_organizations}"
    github_auth_teams = "${var.github_auth_teams}"
    github_auth_users = "${var.github_auth_users}"
  }
}

resource "template_file" "start_concourse_worker" {
  template = "${file("${path.module}/02_start_concourse_worker.sh.tpl")}"

  vars {
    tsa_host = "${aws_elb.web-elb.dns_name}"
    tsa_public_key = "${file("${var.tsa_public_key}")}"
    tsa_worker_private_key = "${file("${var.tsa_worker_private_key}")}"
  }
}

resource "template_cloudinit_config" "web" {
  # Make both turned off until https://github.com/hashicorp/terraform/issues/4794 is fixed
  gzip          = false
  base64_encode = false

  part {
    content_type = "text/x-shellscript"
    content      = "${template_file.install_concourse.rendered}"
  }

  part {
    content_type = "text/x-shellscript"
    content      = "${template_file.start_concourse_web.rendered}"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "template_cloudinit_config" "worker" {
  # Make both turned off until https://github.com/hashicorp/terraform/issues/4794 is fixed
  gzip          = false
  base64_encode = false

  part {
    content_type = "text/x-shellscript"
    content      = "${template_file.install_concourse.rendered}"
  }

  part {
    content_type = "text/x-shellscript"
    content      = "${template_file.start_concourse_worker.rendered}"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "default" {
  name_prefix = "${var.prefix}default"
  description = "concourse ${var.prefix}default"
  vpc_id = "${var.vpc_id}"

  # SSH access from a specific CIDRS
  ingress {
    from_port = 22
    to_port = 22
    protocol = "tcp"
    cidr_blocks = [ "${split(",", var.in_access_allowed_cidrs)}" ]
  }

  # outbound internet access
  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "atc" {
  name_prefix = "${var.prefix}atc"
  description = "concourse ${var.prefix}atc"
  vpc_id = "${var.vpc_id}"

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group_rule" "allow_external_lb_to_atc_access" {
    type = "ingress"
    from_port = "${var.elb_listener_instance_port}"
    to_port = "${var.elb_listener_instance_port}"
    protocol = "tcp"

    security_group_id = "${aws_security_group.tsa.id}"
    source_security_group_id = "${aws_security_group.external_lb.id}"
}

resource "aws_security_group_rule" "allow_atc_to_worker_access" {
    type = "ingress"
    from_port = "0"
    to_port = "65535"
    protocol = "tcp"

    security_group_id = "${aws_security_group.worker.id}"
    source_security_group_id = "${aws_security_group.atc.id}"
}

resource "aws_security_group" "tsa" {
  name_prefix = "${var.prefix}tsa"
  description = "concourse ${var.prefix}tsa"
  vpc_id = "${var.vpc_id}"

  # outbound internet access
  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group_rule" "allow_worker_to_tsa_access" {
    type = "ingress"
    from_port = 2222
    to_port = 2222
    protocol = "tcp"

    security_group_id = "${aws_security_group.tsa.id}"
    source_security_group_id = "${aws_security_group.worker.id}"
}

resource "aws_security_group_rule" "allow_external_lb_to_tsa_access" {
    type = "ingress"
    from_port = 2222
    to_port = 2222
    protocol = "tcp"

    security_group_id = "${aws_security_group.tsa.id}"
    source_security_group_id = "${aws_security_group.external_lb.id}"
}

resource "aws_security_group" "worker" {
  name_prefix = "${var.prefix}worker"
  description = "concourse ${var.prefix}worker"
  vpc_id = "${var.vpc_id}"

  # outbound internet access
  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "external_lb" {
  name_prefix = "${var.prefix}lb"
  description = "concourse ${var.prefix}lb"

  vpc_id = "${var.vpc_id}"

  # HTTP access from a specific CIDRS
  ingress {
    from_port = "${var.elb_listener_lb_port}"
    to_port = "${var.elb_listener_lb_port}"
    protocol = "tcp"
    cidr_blocks = [ "${split(",", var.in_access_allowed_cidrs)}" ]
  }

  ingress {
    from_port = "${var.tsa_port}"
    to_port = "${var.tsa_port}"
    protocol = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "db" {
  name_prefix = "${var.prefix}db"
  description = "concourse ${var.prefix}db"
  vpc_id = "${var.vpc_id}"

  # outbound internet access
  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group_rule" "allow_db_access_from_atc" {
    type = "ingress"
    from_port = 5432
    to_port = 5432
    protocol = "tcp"

    security_group_id = "${aws_security_group.db.id}"
    source_security_group_id = "${aws_security_group.atc.id}"
}

resource "aws_db_instance" "default" {
  depends_on = ["aws_security_group.db"]
  identifier = "${var.prefix}db"
  allocated_storage = "10"
  engine = "postgres"
  engine_version = "${var.db_engine_version}"
  instance_class = "${var.db_instance_class}"
  name = "concourse"
  username = "${var.db_username}"
  password = "${var.db_password}"
  vpc_security_group_ids = ["${aws_security_group.db.id}"]
  db_subnet_group_name = "${aws_db_subnet_group.db.id}"
}

resource "aws_db_subnet_group" "db" {
  name = "${var.prefix}db"
  description = "group of subnets for concourse db"
  subnet_ids = ["${split(",", var.db_subnet_ids)}"]
}

resource "aws_db_subnet_group" "databunkersubnet" {
  name       = "subnet-rds-${var.name_suffix}"
  subnet_ids = module.vpc.private_subnets
  tags = merge({ "Name" = "subnet-rds-${var.name_suffix}"}, var.resource_tags)
}

resource "aws_security_group" "databunkersg" {
  name   = "${var.name_suffix}-sg-rds"
  vpc_id = module.vpc.vpc_id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    #cidr_blocks = module.vpc.private_subnets
  }

  egress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = merge({ "Name" = "${var.name_suffix}-sg-rds"}, var.resource_tags)
}

resource "aws_db_parameter_group" "databunkerparams" {
  name   = "db-params-${var.name_suffix}"
  family = "mysql8.0"

  parameter {
    name = "max_connections"
    value = "4096"
  }

  #parameter {
  #  name  = "log_connections"
  #  value = "1"
  #}
}

resource "aws_db_instance" "databunkerdb" {
  # https://github.com/tmknom/terraform-aws-rds-mysql/blob/master/main.tf
  # The name of the database. If this parameter is not specified, no database is created in the DB instance.
  name                   = "databunkerdb"
  identifier             = "databunkerdb"
  tags                   = merge({ "Name" = "db-${var.name_suffix}"}, var.resource_tags)
  instance_class         = var.ec2_rds_instance_type
  deletion_protection    = var.ec2_rds_deletion_protection
  allocated_storage      = 5
  max_allocated_storage  = 1000
  engine                 = "mysql"
  engine_version         = "8.0.25"
  username               = "bunkeruser"
  #password               = var.db_password
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.databunkersubnet.name
  vpc_security_group_ids = [aws_security_group.databunkersg.id]
  parameter_group_name   = aws_db_parameter_group.databunkerparams.name
  publicly_accessible    = false
  skip_final_snapshot    = true
  # The following list briefly describes the three storage types:
  #
  # - General Purpose SSD – Also known as gp2, volumes offer cost-effective storage that is ideal for a broad range of workloads.
  # - Provisioned IOPS – Also known as io1, that require low I/O latency and consistent I/O throughput.
  # - Magnetic – RDS also supports magnetic storage for backward compatibility.
  #
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/CHAP_Storage.html
  #storage_type = var.storage_type
  # The amount of Provisioned IOPS (input/output operations per second) to be initially allocated for the DB instance.
  # Must be a multiple between 1 and 50 of the storage amount, and range of Provisioned IOPS is 1000–32,000
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/CHAP_Storage.html#USER_PIOPS
  #iops = var.iops
}

resource "kubernetes_secret" "databunker-mysql-rds" {
  metadata {
    name = "databunker-mysql-rds"
  }

  data = {
    #host = aws_db_instance.databunkerdb.address
    #port = aws_db_instance.databunkerdb.port
    #dbname = aws_db_instance.databunkerdb.name
    #username = aws_db_instance.databunkerdb.username
    "db-password" = aws_db_instance.databunkerdb.password
  }
  type = "Opaque"
}

output "rds_hostname" {
  description = "RDS instance hostname"
  value       = aws_db_instance.databunkerdb.address
}

output "rds_port" {
  description = "RDS instance port"
  value       = aws_db_instance.databunkerdb.port
}

output "rds_dbname" {
  description = "RDS database name"
  value = aws_db_instance.databunkerdb.name
}

output "rds_username" {
  description = "RDS instance root username"
  value       = aws_db_instance.databunkerdb.username
}

output "rds_password" {
  description = "RDS instance database password"
  value       = aws_db_instance.databunkerdb.password
  sensitive = true
}

impacted_block_content:
resource "aws_db_subnet_group" "db" {
  name = "${var.prefix}db"
  description = "group of subnets for concourse db"
  subnet_ids = ["${split(",", var.db_subnet_ids)}"]
}

file_content:
# Specify the provider and access details
provider "aws" {
  region = "${var.aws_region}"
}

#module "postgres" {
#    source = "./postgres"
#    access_allowed_security_groups = "${aws_security_group.atc.id}"
#}

module "autoscaling_hooks" {
    source = "./autoscaling/hooks/enabled"
    target_asg_name = "${aws_autoscaling_group.worker-asg.name}"
    prefix = "${var.prefix}"
}

module "autoscaling_schedule" {
    source = "./autoscaling/schedule/enabled"
    target_asg_name = "${aws_autoscaling_group.worker-asg.name}"
    num_workers_during_working_time = 2
    max_num_workers_during_working_time = "${var.asg_max}"
    num_workers_during_non_working_time = 0
}

module "autoscaling_utilization" {
    source = "./autoscaling/utilization/enabled"
    target_asg_name = "${aws_autoscaling_group.worker-asg.name}"
}

resource "aws_elb" "web-elb" {
  name = "${var.prefix}concourse-lb"

  # The same availability zone as our instances
  # Only one of SubnetIds or AvailabilityZones may be specified
  #availability_zones = ["${split(",", var.availability_zones)}"]
  security_groups = ["${aws_security_group.external_lb.id}"]
  subnets = ["${split(",", var.subnet_id)}"]
  cross_zone_load_balancing = "true"

  listener {
    instance_port = "${var.elb_listener_instance_port}"
    instance_protocol = "http"
    lb_port = "${var.elb_listener_lb_port}"
    lb_protocol = "${var.elb_listener_lb_protocol}"
    ssl_certificate_id = "${var.ssl_certificate_arn}"
  }

  listener {
    instance_port = "${var.tsa_port}"
    instance_protocol = "tcp"
    lb_port = "${var.tsa_port}"
    lb_protocol = "tcp"
  }

  health_check {
    healthy_threshold = 2
    unhealthy_threshold = 2
    timeout = 3
    target = "TCP:${var.elb_listener_instance_port}"
    interval = 30
  }
}

resource "aws_autoscaling_group" "web-asg" {
  # See "Phasing in" an Autoscaling Group? https://groups.google.com/forum/#!msg/terraform-tool/7Gdhv1OAc80/iNQ93riiLwAJ
  # * Recreation of the launch configuration triggers recreation of this ASG and its EC2 instances
  # * Modification to the lc (change to referring AMI) triggers recreation of this ASG
  name = "${var.prefix}${aws_launch_configuration.web-lc.name}${var.ami}"
  availability_zones = ["${split(",", var.availability_zones)}"]
  max_size = "${var.asg_max}"
  min_size = "${var.asg_min}"
  desired_capacity = "${var.web_asg_desired}"
  launch_configuration = "${aws_launch_configuration.web-lc.name}"
  load_balancers = ["${aws_elb.web-elb.name}"]
  vpc_zone_identifier = ["${split(",", var.subnet_id)}"]
  tag {
    key = "Name"
    value = "${var.prefix}web"
    propagate_at_launch = "true"
  }
  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_autoscaling_group" "worker-asg" {
  name = "${var.prefix}${aws_launch_configuration.worker-lc.name}${var.ami}"
  availability_zones = ["${split(",", var.availability_zones)}"]
  max_size = "${var.asg_max}"
  min_size = "${var.asg_min}"
  desired_capacity = "${var.worker_asg_desired}"
  launch_configuration = "${aws_launch_configuration.worker-lc.name}"
  vpc_zone_identifier = ["${split(",", var.subnet_id)}"]
  tag {
    key = "Name"
    value = "${var.prefix}worker"
    propagate_at_launch = "true"
  }
  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_launch_configuration" "web-lc" {
  # Omit launch configuration name to avoid collisions on create_before_destroy
  # ref. https://github.com/hashicorp/terraform/issues/1109#issuecomment-97970885
  #image_id = "${lookup(var.aws_amis, var.aws_region)}"
  image_id = "${var.ami}"
  instance_type = "${var.web_instance_type}"
  security_groups = ["${aws_security_group.default.id}","${aws_security_group.atc.id}","${aws_security_group.tsa.id}"]
  user_data = "${template_cloudinit_config.web.rendered}"
  key_name = "${var.key_name}"
  associate_public_ip_address = true
  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_launch_configuration" "worker-lc" {
  #image_id = "${lookup(var.aws_amis, var.aws_region)}"
  image_id = "${var.ami}"
  instance_type = "${var.worker_instance_type}"
  security_groups = ["${aws_security_group.default.id}", "${aws_security_group.worker.id}"]
  user_data = "${template_cloudinit_config.worker.rendered}"
  key_name = "${var.key_name}"
  associate_public_ip_address = true
  iam_instance_profile = "${var.worker_instance_profile}"
  root_block_device {
    # For fast booting, we use gp2
    volume_type = "gp2"
    # You need enough capacity to avoid the following error while docker export & untar'ing:
    #
    # *snip*
    # tar: etc/alternatives: Cannot stat: Input/output error
    # tar: etc: Cannot stat: Input/output error
    # tar: dev: Cannot stat: Input/output error
    # tar: bin: Cannot stat: Input/output error
    # tar: Exiting with failure status due to previous errors
    #
    # resource script '/opt/resource/in [/tmp/build/get]' failed: exit status 2
    #
    # Or the following error when tried to run the job:
    # resource_pool: creating container directory: mkdir /var/lib/concourse/linux/depot/hntrh2no0mh: no space left on device
    volume_size = "50"
    delete_on_termination = true
  }
  lifecycle {
    create_before_destroy = true
  }
}

resource "template_file" "install_concourse" {
  template = "${file("${path.module}/00_install_concourse.sh.tpl")}"
}

resource "template_file" "start_concourse_web" {
  template = "${file("${path.module}/01_start_concourse_web.sh.tpl")}"

  vars {
    session_signing_key = "${file("${var.session_signing_key}")}"
    tsa_host_key = "${file("${var.tsa_host_key}")}"
    tsa_authorized_keys = "${file("${var.tsa_authorized_keys}")}"
    postgres_data_source = "postgres://${var.db_username}:${var.db_password}@${aws_db_instance.default.endpoint}/concourse"
    external_url = "${var.elb_listener_lb_protocol}://${element(split(",","${aws_elb.web-elb.dns_name},${var.custom_external_domain_name}"), var.use_custom_external_domain_name)}${element(split(",",",:${var.elb_listener_lb_port}"), var.use_custom_elb_port)}"
    basic_auth_username = "${var.basic_auth_username}"
    basic_auth_password = "${var.basic_auth_password}"
    github_auth_client_id = "${var.github_auth_client_id}"
    github_auth_client_secret = "${var.github_auth_client_secret}"
    github_auth_organizations = "${var.github_auth_organizations}"
    github_auth_teams = "${var.github_auth_teams}"
    github_auth_users = "${var.github_auth_users}"
  }
}

resource "template_file" "start_concourse_worker" {
  template = "${file("${path.module}/02_start_concourse_worker.sh.tpl")}"

  vars {
    tsa_host = "${aws_elb.web-elb.dns_name}"
    tsa_public_key = "${file("${var.tsa_public_key}")}"
    tsa_worker_private_key = "${file("${var.tsa_worker_private_key}")}"
  }
}

resource "template_cloudinit_config" "web" {
  # Make both turned off until https://github.com/hashicorp/terraform/issues/4794 is fixed
  gzip          = false
  base64_encode = false

  part {
    content_type = "text/x-shellscript"
    content      = "${template_file.install_concourse.rendered}"
  }

  part {
    content_type = "text/x-shellscript"
    content      = "${template_file.start_concourse_web.rendered}"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "template_cloudinit_config" "worker" {
  # Make both turned off until https://github.com/hashicorp/terraform/issues/4794 is fixed
  gzip          = false
  base64_encode = false

  part {
    content_type = "text/x-shellscript"
    content      = "${template_file.install_concourse.rendered}"
  }

  part {
    content_type = "text/x-shellscript"
    content      = "${template_file.start_concourse_worker.rendered}"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "default" {
  name_prefix = "${var.prefix}default"
  description = "concourse ${var.prefix}default"
  vpc_id = "${var.vpc_id}"

  # SSH access from a specific CIDRS
  ingress {
    from_port = 22
    to_port = 22
    protocol = "tcp"
    cidr_blocks = [ "${split(",", var.in_access_allowed_cidrs)}" ]
  }

  # outbound internet access
  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "atc" {
  name_prefix = "${var.prefix}atc"
  description = "concourse ${var.prefix}atc"
  vpc_id = "${var.vpc_id}"

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group_rule" "allow_external_lb_to_atc_access" {
    type = "ingress"
    from_port = "${var.elb_listener_instance_port}"
    to_port = "${var.elb_listener_instance_port}"
    protocol = "tcp"

    security_group_id = "${aws_security_group.tsa.id}"
    source_security_group_id = "${aws_security_group.external_lb.id}"
}

resource "aws_security_group_rule" "allow_atc_to_worker_access" {
    type = "ingress"
    from_port = "0"
    to_port = "65535"
    protocol = "tcp"

    security_group_id = "${aws_security_group.worker.id}"
    source_security_group_id = "${aws_security_group.atc.id}"
}

resource "aws_security_group" "tsa" {
  name_prefix = "${var.prefix}tsa"
  description = "concourse ${var.prefix}tsa"
  vpc_id = "${var.vpc_id}"

  # outbound internet access
  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group_rule" "allow_worker_to_tsa_access" {
    type = "ingress"
    from_port = 2222
    to_port = 2222
    protocol = "tcp"

    security_group_id = "${aws_security_group.tsa.id}"
    source_security_group_id = "${aws_security_group.worker.id}"
}

resource "aws_security_group_rule" "allow_external_lb_to_tsa_access" {
    type = "ingress"
    from_port = 2222
    to_port = 2222
    protocol = "tcp"

    security_group_id = "${aws_security_group.tsa.id}"
    source_security_group_id = "${aws_security_group.external_lb.id}"
}

resource "aws_security_group" "worker" {
  name_prefix = "${var.prefix}worker"
  description = "concourse ${var.prefix}worker"
  vpc_id = "${var.vpc_id}"

  # outbound internet access
  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "external_lb" {
  name_prefix = "${var.prefix}lb"
  description = "concourse ${var.prefix}lb"

  vpc_id = "${var.vpc_id}"

  # HTTP access from a specific CIDRS
  ingress {
    from_port = "${var.elb_listener_lb_port}"
    to_port = "${var.elb_listener_lb_port}"
    protocol = "tcp"
    cidr_blocks = [ "${split(",", var.in_access_allowed_cidrs)}" ]
  }

  ingress {
    from_port = "${var.tsa_port}"
    to_port = "${var.tsa_port}"
    protocol = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "db" {
  name_prefix = "${var.prefix}db"
  description = "concourse ${var.prefix}db"
  vpc_id = "${var.vpc_id}"

  # outbound internet access
  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group_rule" "allow_db_access_from_atc" {
    type = "ingress"
    from_port = 5432
    to_port = 5432
    protocol = "tcp"

    security_group_id = "${aws_security_group.db.id}"
    source_security_group_id = "${aws_security_group.atc.id}"
}

resource "aws_db_instance" "default" {
  depends_on = ["aws_security_group.db"]
  identifier = "${var.prefix}db"
  allocated_storage = "10"
  engine = "postgres"
  engine_version = "${var.db_engine_version}"
  instance_class = "${var.db_instance_class}"
  name = "concourse"
  username = "${var.db_username}"
  password = "${var.db_password}"
  vpc_security_group_ids = ["${aws_security_group.db.id}"]
  db_subnet_group_name = "${aws_db_subnet_group.db.id}"
}

resource "aws_db_subnet_group" "db" {
  name = "${var.prefix}db"
  description = "group of subnets for concourse db"
  subnet_ids = ["${split(",", var.db_subnet_ids)}"]
}

impacted_block_content:
resource "aws_dynamodb_table" "ecs-deploy" {
  name           = "ecs-deploy"
  read_capacity  = var.dynamodb_read_capacity
  write_capacity = var.dynamodb_write_capacity
  hash_key       = "ServiceName"
  range_key      = "Time"

  dynamic "point_in_time_recovery" {
    for_each = var.enable_dynamodb_pitr ? ["enabled"] : []
    content {
      enabled = var.enable_dynamodb_pitr
      recovery_period_in_days = var.dynamodb_pitr_recovery_period
    }
  }
  server_side_encryption {
    enabled = var.enable_dynamodb_encryption
  }

  attribute {
    name = "ServiceName"
    type = "S"
  }

  attribute {
    name = "Time"
    type = "S"
  }

  attribute {
    name = "Day"
    type = "S"
  }

  attribute {
    name = "Month"
    type = "S"
  }

  ttl {
    attribute_name = "ExpirationTimeTTL"
    enabled        = true
  }

  global_secondary_index {
    name            = "DayIndex"
    hash_key        = "Day"
    range_key       = "Time"
    write_capacity  = 2
    read_capacity   = 2
    projection_type = "ALL"
  }

  global_secondary_index {
    name            = "MonthIndex"
    hash_key        = "Month"
    range_key       = "Time"
    write_capacity  = 2
    read_capacity   = 2
    projection_type = "ALL"
  }
}

file_content:
#
# ecs-deploy
#

#
# accountid
#
data "aws_caller_identity" "current" {
}

#
# ECS service
#

resource "aws_ecs_service" "ecs-deploy" {
  name                               = "ecs-deploy"
  cluster                            = aws_ecs_cluster.cluster.id
  task_definition                    = var.ecs_deploy_enable_appmesh ? aws_ecs_task_definition.ecs-deploy-appmesh[0].arn : aws_ecs_task_definition.ecs-deploy[0].arn
  iam_role                           = var.ecs_deploy_awsvpc ? "" : aws_iam_role.cluster-service-role.arn
  desired_count                      = 1
  deployment_minimum_healthy_percent = 100
  deployment_maximum_percent         = 200

  dynamic "network_configuration" {
    for_each = var.ecs_deploy_awsvpc ? ["enabled"] : []
    content {
      subnets          = var.vpc_private_subnets
      security_groups  = [aws_security_group.ecs-deploy-awsvpc.id]
      assign_public_ip = false
    }
  }

  dynamic "service_registries" {
    for_each = var.ecs_deploy_service_discovery_id == "" ? [] : ["enabled"]
    content {
      registry_arn = aws_service_discovery_service.ecs-deploy[0].arn
    }
  }

  load_balancer {
    target_group_arn = aws_alb_target_group.ecs-deploy.id
    container_name   = "ecs-deploy"
    container_port   = 8080
  }
}

locals {
  template_vars = {
    AWS_REGION            = var.aws_region
    ENVIRONMENT           = var.aws_env
    PARAMSTORE_ENABLED    = var.paramstore_enabled
    CLUSTER_NAME          = var.cluster_name
    ECS_DEPLOY_IMAGE      = var.ecs_deploy_image
    ECS_DEPLOY_VERSION    = var.ecs_deploy_version
    DEBUG                 = var.ecs_deploy_debug
    APPMESH_NAME          = var.ecs_deploy_appmesh_name
    APPMESH_ENVOY_RELEASE = var.ecs_deploy_appmesh_release
    ECS_WHITELIST         = var.ecs_whitelist
    PROD_CODE             = var.prod_code

    ECS_DEPLOY_CPU                = var.ecs_deploy_cpu
    ECS_DEPLOY_MEMORY_RESERVATION = var.ecs_deploy_memory_reservation
  }
}

resource "aws_ecs_task_definition" "ecs-deploy" {
  count                 = var.ecs_deploy_enable_appmesh ? 0 : 1
  family                = "ecs-deploy"
  container_definitions = var.ecs_deploy_enable_appmesh ? templatefile("${path.module}/templates/ecs-deploy-appmesh.json", local.template_vars) : templatefile("${path.module}/templates/ecs-deploy.json", local.template_vars)
  task_role_arn         = aws_iam_role.ecs-deploy.arn
  network_mode          = var.ecs_deploy_awsvpc ? "awsvpc" : "bridge"
  execution_role_arn    = var.ecs_deploy_awsvpc ? aws_iam_role.ecs-task-execution-role.arn : ""
}

resource "aws_ecs_task_definition" "ecs-deploy-appmesh" {
  count                 = var.ecs_deploy_enable_appmesh ? 1 : 0
  family                = "ecs-deploy"
  container_definitions = var.ecs_deploy_enable_appmesh ? templatefile("${path.module}/templates/ecs-deploy-appmesh.json", local.template_vars) : templatefile("${path.module}/templates/ecs-deploy.json", local.template_vars)
  task_role_arn         = aws_iam_role.ecs-deploy.arn
  network_mode          = var.ecs_deploy_awsvpc ? "awsvpc" : "bridge"
  execution_role_arn    = var.ecs_deploy_awsvpc ? aws_iam_role.ecs-task-execution-role.arn : ""

  proxy_configuration {
    type           = "APPMESH"
    container_name = "envoy"
    properties = {
      AppPorts         = "10000"
      EgressIgnoredIPs = "169.254.170.2,169.254.169.254"
      IgnoredUID       = "1337"
      ProxyEgressPort  = 15001
      ProxyIngressPort = 15000
    }
  }
}

#
# IAM role & policy
#
resource "aws_iam_role" "ecs-deploy" {
  name = "ecs-deploy"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "ecs-tasks.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
EOF

}

resource "aws_iam_role_policy" "ecs-deploy-policy" {
  name = "ecs-deploy-policy"
  role = aws_iam_role.ecs-deploy.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "ecs:DeregisterContainerInstance",
        "ecs:DiscoverPollEndpoint",
        "ecs:Poll",
        "ecs:RegisterContainerInstance",
        "ecs:StartTelemetrySession",
        "ecs:Submit*",
        "ecs:StartTask",
        "ecs:Describe*",
        "ecs:List*",
        "ecs:UpdateService",
        "ecs:CreateService",
        "ecs:RegisterTaskDefinition",
        "ecs:UpdateContainerInstancesState",
        "ecr:GetAuthorizationToken",
        "ecr:BatchCheckLayerAvailability",
        "ecr:GetDownloadUrlForLayer",
        "ecr:GetRepositoryPolicy",
        "ecr:DescribeRepositories",
        "ecr:ListImages",
        "ecr:DescribeImages",
        "ecr:BatchGetImage",
        "ecr:InitiateLayerUpload",
        "ecr:UploadLayerPart",
        "ecr:CompleteLayerUpload",
        "ecr:PutImage",
        "ecr:CreateRepository",
        "ecr:PutLifecyclePolicy",
        "elasticloadbalancing:Describe*",
        "elasticloadbalancing:CreateRule",
        "elasticloadbalancing:DeleteRule",
        "elasticloadbalancing:CreateTargetGroup",
        "elasticloadbalancing:DeleteTargetGroup",
        "elasticloadbalancing:ModifyTargetGroupAttributes",
        "acm:DescribeCertificate",
        "autoscaling:DescribeAutoScalingGroups",
        "autoscaling:DescribeLifecycleHooks",
        "autoscaling:DescribeAutoScalingNotificationTypes",
        "autoscaling:UpdateAutoScalingGroup",
        "autoscaling:CompleteLifecycleAction",
        "logs:GetLogEvents",
        "ec2:DescribeTags",
        "ec2:DescribeSecurityGroups",
        "ec2:DescribeSubnets",
        "cloudwatch:PutMetricAlarm",
        "cloudwatch:DescribeAlarms",
        "cloudwatch:DeleteAlarms",
        "application-autoscaling:PutScalingPolicy",
        "application-autoscaling:RegisterScalableTarget",
        "application-autoscaling:DeregisterScalableTarget",
        "application-autoscaling:DescribeScalableTargets",
        "application-autoscaling:DescribeScalingPolicies",
        "application-autoscaling:DeleteScalingPolicy",
        "servicediscovery:ListNamespaces",
        "servicediscovery:ListServices",
        "servicediscovery:CreateService",
        "ssm:GetParametersByPath",
        "cognito-idp:DescribeUserPool",
        "cognito-idp:DescribeUserPoolClient",
        "cognito-idp:ListUserPoolClients",
        "cognito-idp:ListUserPools",
        "appmesh:CreateVirtualNode",
        "appmesh:CreateVirtualService",
        "appmesh:CreateVirtualRouter",
        "appmesh:CreateRoute",
        "appmesh:UpdateVirtualNode",
        "appmesh:UpdateVirtualService",
        "appmesh:UpdateVirtualRouter",
        "appmesh:UpdateRoute",
        "appmesh:ListVirtualNodes",
        "appmesh:ListVirtualServices",
        "appmesh:ListVirtualNodes",
        "appmesh:ListVirtualServices",
        "appmesh:ListVirtualRouters",
        "appmesh:ListRoutes"
      ],
      "Resource": "*"
    },
    {
      "Effect": "Allow",
      "Action": [
          "iam:CreateRole",
          "iam:AttachRolePolicy",
          "iam:PutRolePolicy",
          "iam:GetRole",
          "iam:PassRole"
      ],
      "Resource": "arn:aws:iam::*:role/ecs-*"
    },
    {
      "Action": [
        "ssm:GetParameterHistory",
        "ssm:GetParameter",
        "ssm:GetParameters",
        "ssm:GetParametersByPath"
      ],
      "Resource": [
        "arn:aws:ssm:${var.aws_region}:${data.aws_caller_identity.current.account_id}:parameter/${var.cluster_name}-${var.aws_env}/ecs-deploy/*"
      ],
      "Effect": "Allow"
    },
    {
      "Action": [
        "kms:Decrypt"
      ],
      "Resource": [
        "${data.aws_kms_key.ssm.arn}"
      ],
      "Effect": "Allow"
    },
    {
      "Effect": "Allow",
      "Action": [
          "dynamodb:*"
      ],
      "Resource": [
        "arn:aws:dynamodb:${var.aws_region}:${data.aws_caller_identity.current.account_id}:table/ecs-deploy",
        "arn:aws:dynamodb:${var.aws_region}:${data.aws_caller_identity.current.account_id}:table/ecs-deploy/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": [
        "aws-marketplace:RegisterUsage"
      ],
      "Resource": "*"
    }
  ]
}
EOF

}

#
# dynamodb
#
resource "aws_dynamodb_table" "ecs-deploy" {
  name           = "ecs-deploy"
  read_capacity  = var.dynamodb_read_capacity
  write_capacity = var.dynamodb_write_capacity
  hash_key       = "ServiceName"
  range_key      = "Time"

  dynamic "point_in_time_recovery" {
    for_each = var.enable_dynamodb_pitr ? ["enabled"] : []
    content {
      enabled = var.enable_dynamodb_pitr
      recovery_period_in_days = var.dynamodb_pitr_recovery_period
    }
  }
  server_side_encryption {
    enabled = var.enable_dynamodb_encryption
  }

  attribute {
    name = "ServiceName"
    type = "S"
  }

  attribute {
    name = "Time"
    type = "S"
  }

  attribute {
    name = "Day"
    type = "S"
  }

  attribute {
    name = "Month"
    type = "S"
  }

  ttl {
    attribute_name = "ExpirationTimeTTL"
    enabled        = true
  }

  global_secondary_index {
    name            = "DayIndex"
    hash_key        = "Day"
    range_key       = "Time"
    write_capacity  = 2
    read_capacity   = 2
    projection_type = "ALL"
  }

  global_secondary_index {
    name            = "MonthIndex"
    hash_key        = "Month"
    range_key       = "Time"
    write_capacity  = 2
    read_capacity   = 2
    projection_type = "ALL"
  }
}

# cloudwatch log group
resource "aws_cloudwatch_log_group" "ecs-deploy" {
  name              = "ecs-deploy"
  kms_key_id        = var.cloudwatch_log_group_kms_arn
  retention_in_days = var.cloudwatch_log_retention_period
}

#
# webhook and autoscaling hook
#
# sns topic for ecs events
resource "aws_sns_topic" "ecs-deploy" {
  count             = var.ecs_capacity_provider_enabled ? 0 : 1
  name              = "ecs-deploy-events"
  kms_master_key_id = var.sns_kms_master_key_id
  policy = <<EOF
{
  "Version": "2008-10-17",
  "Id": "__default_policy_ID",
  "Statement": [
    {
      "Sid": "__default_statement_ID",
      "Effect": "Allow",
      "Principal": {
        "AWS": "*"
      },
      "Action": [
        "SNS:GetTopicAttributes",
        "SNS:SetTopicAttributes",
        "SNS:AddPermission",
        "SNS:RemovePermission",
        "SNS:DeleteTopic",
        "SNS:Subscribe",
        "SNS:ListSubscriptionsByTopic",
        "SNS:Publish",
        "SNS:Receive"
      ],
      "Resource": "arn:aws:sns:${var.aws_region}:${data.aws_caller_identity.current.account_id}:ecs-deploy-events",
      "Condition": {
        "StringEquals": {
          "AWS:SourceOwner": "${data.aws_caller_identity.current.account_id}"
        }
      }
    },
    {
      "Sid": "TrustCWEToPublishEventsToMyTopic",
      "Effect": "Allow",
      "Principal": {
        "Service": "events.amazonaws.com"
      },
      "Action": "sns:Publish",
      "Resource": "arn:aws:sns:${var.aws_region}:${data.aws_caller_identity.current.account_id}:ecs-deploy-events"
    }
  ]
}
EOF

}

# post sns to ecs-deploy(https)
resource "aws_sns_topic_subscription" "ecs-deploy" {
  count = var.ecs_capacity_provider_enabled ? 0 : 1
  topic_arn              = aws_sns_topic.ecs-deploy[0].arn
  protocol               = "https"
  endpoint               = "https://${var.sns_endpoint == "" ? var.cluster_domain : var.sns_endpoint}/ecs-deploy/webhook"
  endpoint_auto_confirms = true
}

# Watch for ecs events in the logs
resource "aws_cloudwatch_event_rule" "ecs-deploy" {
  count = var.ecs_capacity_provider_enabled ? 0 : 1
  name        = "ecs-event"
  description = "Capture ecs events"

  event_pattern = <<PATTERN
{
  "source": [
    "aws.ecs"
  ],
  "detail-type": [
    "ECS Container Instance State Change",
    "ECS Task State Change"
  ],
  "detail": {
    "clusterArn": [
      "${aws_ecs_cluster.cluster.id}"
    ]
  }
}
PATTERN

}

# Send ecs-events to sns
resource "aws_cloudwatch_event_target" "ecs-deploy" {
  count = var.ecs_capacity_provider_enabled ? 0 : 1
  rule      = aws_cloudwatch_event_rule.ecs-deploy[0].name
  target_id = "SendEcsEventToSNS"
  arn       = aws_sns_topic.ecs-deploy[0].arn
}

# cloudwatch event for autoscaling
resource "aws_cloudwatch_event_rule" "ecs-deploy-autoscaling" {
  count = var.ecs_capacity_provider_enabled ? 0 : 1
  name        = "ecs-deploy-autoscaling"
  description = "Capture autoscaling events"

  event_pattern = <<PATTERN
{
  "source": [
    "aws.autoscaling"
  ],
  "detail-type": [
    "EC2 Instance-terminate Lifecycle Action"
  ],
  "detail": {
    "LifecycleHookName": [
      "${aws_autoscaling_lifecycle_hook.cluster[0].name}"
    ]
  }
}
PATTERN

}

# Send ecs-events to sns
resource "aws_cloudwatch_event_target" "ecs-deploy-autoscaling" {
  count = var.ecs_capacity_provider_enabled ? 0 : 1
  rule      = aws_cloudwatch_event_rule.ecs-deploy-autoscaling[0].name
  target_id = "SendAutoscalingEventToSNS"
  arn       = aws_sns_topic.ecs-deploy[0].arn
}

