  "Statement": [
    {
    "Action": [
        "s3:ListBucket"
      ],
      "Effect": "Allow",
      "Resource": [
          "arn:aws:s3:::${aws_s3_bucket.frontend_code.id}",
          "arn:aws:s3:::${aws_s3_bucket.backend_code.id}"
          ]
    },
    {
      "Action": [
        "s3:PutObject",
        "s3:GetObject"
      ],
      "Effect": "Allow",
      "Resource": [
