resource "aws_lambda_function" "example_lambda" {
    function_name           = "${local.product}-example-lambda${local.environment}"
    role                    = aws_iam_role.lambda.arn
    filename                = data.archive_file.dummy.output_path
    handler                 = "example_handler.run_lambda"
    runtime                 = "python3.9"
    description             = "Run example lambda"
    timeout                 = local.lambda_timeout
    environment {
        variables = {
            SECRETS_MANAGER_ENDPOINT = "https://secretsmanager.${var.aws_region}.amazonaws.com"
        }
    }

    # vpc_config {
        # subnet_ids = data.aws_subnets.private_app_subnets.ids 
        # security_group_ids = [data.aws_security_group.gps_rds_sg.id]
    # }

    tags                    = merge(local.product_tags, map("name", "example-lambda"))
}

