resource "aws_lb" "test_lb" {
  name            = "${var.elb_name}-lb"
  internal        = false
  security_groups = ["${aws_security_group.allow_http.id}"]
  subnets         = aws_subnet.test_elb.*.id

  depends_on = [
    "aws_internet_gateway.gateway",
    "aws_s3_bucket_policy.write_logs",
  ]

  access_logs {
    enabled = true
    bucket  = "${aws_s3_bucket.test_elb_logs.bucket}"
    prefix  = "httplb"
  }
}

file_content:
resource "aws_lb" "test_lb" {
  name            = "${var.elb_name}-lb"
  internal        = false
  security_groups = ["${aws_security_group.allow_http.id}"]
  subnets         = aws_subnet.test_elb.*.id

  depends_on = [
    "aws_internet_gateway.gateway",
    "aws_s3_bucket_policy.write_logs",
  ]

  access_logs {
    enabled = true
    bucket  = "${aws_s3_bucket.test_elb_logs.bucket}"
    prefix  = "httplb"
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = "${aws_lb.test_lb.arn}"
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = "${aws_lb_target_group.instances.arn}"
  }
}

resource "aws_lb_target_group" "instances" {
  name     = "test-lb-instances"
  port     = 80
  protocol = "HTTP"
  vpc_id   = "${aws_vpc.test_elb.id}"
}

resource "aws_lb_target_group_attachment" "instances" {
  count = length(aws_instance.webserver_backend.*)

  port = 80

  target_id        = "${aws_instance.webserver_backend[count.index].id}"
  target_group_arn = "${aws_lb_target_group.instances.arn}"
}

output "lb_http_address" {
  value = "${aws_lb.test_lb.dns_name}"
}

impacted_block_content:
resource "aws_lb_listener_rule" "setup_mpc_map" {
  listener_arn = "${data.terraform_remote_state.setup_iac.outputs.alb_listener_arn}"
  priority     = 300

  action {
    type             = "forward"
    target_group_arn = "${aws_alb_target_group.setup_mpc_map.arn}"
  }

  condition {
    field  = "path-pattern"
    values = ["*"]
  }
}

file_content:
terraform {
  backend "s3" {
    bucket = "aztec-terraform"
    key    = "setup/setup-mpc-map"
    region = "eu-west-2"
  }
}

data "terraform_remote_state" "setup_iac" {
  backend = "s3"
  config = {
    bucket = "aztec-terraform"
    key    = "setup/setup-iac"
    region = "eu-west-2"
  }
}

provider "aws" {
  profile = "default"
  region  = "eu-west-2"
}

resource "aws_service_discovery_service" "setup_mpc_map" {
  name = "setup-mpc-map"

  health_check_custom_config {
    failure_threshold = 1
  }

  dns_config {
    namespace_id = "${data.terraform_remote_state.setup_iac.outputs.local_service_discovery_id}"

    dns_records {
      ttl  = 10
      type = "A"
    }

    routing_policy = "MULTIVALUE"
  }
}

resource "aws_ecs_task_definition" "setup_mpc_map" {
  family                   = "setup-mpc-map"
  requires_compatibilities = ["FARGATE"]
  network_mode             = "awsvpc"
  cpu                      = "256"
  memory                   = "512"
  execution_role_arn       = "${data.terraform_remote_state.setup_iac.outputs.ecs_task_execution_role_arn}"

  container_definitions = <<DEFINITIONS
[
  {
    "name": "setup-mpc-map",
    "image": "278380418400.dkr.ecr.eu-west-2.amazonaws.com/setup-mpc-map:latest",
    "essential": true,
    "portMappings": [
      {
        "containerPort": 80
      }
    ],
    "environment": [
      {
        "name": "NODE_ENV",
        "value": "production"
      },
      {
        "name": "PORT",
        "value": "80"
      }
    ],
    "logConfiguration": {
      "logDriver": "awslogs",
      "options": {
        "awslogs-group": "/fargate/service/setup-mpc-map",
        "awslogs-region": "eu-west-2",
        "awslogs-stream-prefix": "ecs"
      }
    }
  }
]
DEFINITIONS
}

data "aws_ecs_task_definition" "setup_mpc_map" {
  task_definition = "${aws_ecs_task_definition.setup_mpc_map.family}"
}

resource "aws_ecs_service" "setup_mpc_map" {
  name          = "setup-mpc-map"
  cluster       = "${data.terraform_remote_state.setup_iac.outputs.ecs_cluster_id}"
  launch_type   = "FARGATE"
  desired_count = "1"

  network_configuration {
    subnets = [
      "${data.terraform_remote_state.setup_iac.outputs.subnet_az1_private_id}",
      "${data.terraform_remote_state.setup_iac.outputs.subnet_az2_private_id}"
    ]
    security_groups = ["${data.terraform_remote_state.setup_iac.outputs.security_group_private_id}"]
  }

  load_balancer {
    target_group_arn = "${aws_alb_target_group.setup_mpc_map.arn}"
    container_name   = "setup-mpc-map"
    container_port   = 80
  }

  service_registries {
    registry_arn = "${aws_service_discovery_service.setup_mpc_map.arn}"
  }

  # Track the latest ACTIVE revision
  task_definition = "${aws_ecs_task_definition.setup_mpc_map.family}:${max("${aws_ecs_task_definition.setup_mpc_map.revision}", "${data.aws_ecs_task_definition.setup_mpc_map.revision}")}"

  lifecycle {
    ignore_changes = ["task_definition"]
  }
}

# Logs
resource "aws_cloudwatch_log_group" "setup_mpc_map_logs" {
  name              = "/fargate/service/setup-mpc-map"
  retention_in_days = "14"
}

# Configure ALB route.
resource "aws_alb_target_group" "setup_mpc_map" {
  name        = "setup-mpc-map"
  port        = "80"
  protocol    = "HTTP"
  target_type = "ip"
  vpc_id      = "${data.terraform_remote_state.setup_iac.outputs.vpc_id}"
  tags = {
    name = "setup-mpc-map"
  }
}

resource "aws_lb_listener_rule" "setup_mpc_map" {
  listener_arn = "${data.terraform_remote_state.setup_iac.outputs.alb_listener_arn}"
  priority     = 300

  action {
    type             = "forward"
    target_group_arn = "${aws_alb_target_group.setup_mpc_map.arn}"
  }

  condition {
    field  = "path-pattern"
    values = ["*"]
  }
}

