resource "aws_nat_gateway" "gw" {
  allocation_id = "${aws_eip.nat.id}"
  subnet_id = "${aws_subnet.public.id}"

  tags = {
    Name = "H2ODeploymentGateway"
  }

  depends_on = ["aws_internet_gateway.gw", "aws_subnet.public", "aws_subnet.public2"]
}

file_content:
##
## Provider definition
##
provider "aws" {
  region = "${var.aws_region}"
  access_key = "${var.aws_access_key}"
  secret_key = "${var.aws_secret_key}"
}

##
## VPC - if user did not specify aws_vpc_id
##
resource "aws_vpc" "main" {
  cidr_block = "${var.aws_vpc_cidr_block}"
  enable_dns_hostnames = true
  enable_dns_support = true
  enable_classiclink = false
  enable_classiclink_dns_support = false

  tags = {
    Name = "H2ODeployment"
  }
}


##
## VPC Subnet
##

resource "aws_subnet" "public" {
  vpc_id = "${aws_vpc.main.id}"
  cidr_block = "${var.aws_subnet_public_cidr_block}"
  availability_zone = "${var.aws_availability_zone}"
  map_public_ip_on_launch = "true"
  tags = {
    name = "H2ODeploymentSubnetPublic"
  }
}

resource "aws_subnet" "public2" {
  vpc_id = "${aws_vpc.main.id}"
  cidr_block = "${var.aws_subnet_public2_cidr_block}"
  availability_zone = "${var.aws_availability_zone2}"
  map_public_ip_on_launch = "true"
  tags = {
    name = "H2ODeploymentSubnetPublic2"
  }
}

resource "aws_subnet" "main" {
  vpc_id = "${aws_vpc.main.id}"
  cidr_block = "${var.aws_subnet_main_cidr_block}"
  availability_zone = "${var.aws_availability_zone}"
  tags = {
    name = "H2ODeploymentSubnetMain"
  }
  depends_on = ["aws_subnet.public"]
}

##
## Internet Gateway
##
resource "aws_internet_gateway" "gw" {
  vpc_id = "${aws_vpc.main.id}"
}

resource "aws_eip" "nat" {
  vpc = true
}

resource "aws_nat_gateway" "gw" {
  allocation_id = "${aws_eip.nat.id}"
  subnet_id = "${aws_subnet.public.id}"

  tags = {
    Name = "H2ODeploymentGateway"
  }

  depends_on = ["aws_internet_gateway.gw", "aws_subnet.public", "aws_subnet.public2"]
}

##
## Route table (mainly for gateway)
## 
resource "aws_route_table" "r" {
  vpc_id = "${aws_vpc.main.id}"

  route {
    cidr_block = "0.0.0.0/0"
    nat_gateway_id = "${aws_nat_gateway.gw.id}"
  }
}

resource "aws_route_table" "r-public" {
  vpc_id = "${aws_vpc.main.id}"
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = "${aws_internet_gateway.gw.id}"
  }
}

resource "aws_route_table_association" "a-public" {
  subnet_id = "${aws_subnet.public.id}"
  route_table_id = "${aws_route_table.r-public.id}"
}

resource "aws_route_table_association" "a-public2" {
  subnet_id = "${aws_subnet.public2.id}"
  route_table_id = "${aws_route_table.r-public.id}"
}

##
## Associate the route table with the VPC
##
resource "aws_main_route_table_association" "a" {
  vpc_id = "${aws_vpc.main.id}"
  route_table_id = "${aws_route_table.r.id}"
}

##
## Create DHCP Options
##
resource "aws_vpc_dhcp_options" "main" {
  domain_name = "ec2.internal"
  domain_name_servers = [
    "AmazonProvidedDNS"]
  tags = {
    Name = "H2ODeploymentDHCPOptions"
  }
}

##
## Associate DHCP options with the VPC
##
resource "aws_vpc_dhcp_options_association" "dns_resolver" {
  vpc_id = "${aws_vpc.main.id}"
  dhcp_options_id = "${aws_vpc_dhcp_options.main.id}"
}

resource "aws_security_group" "db" {
  name = "vpc_db"
  description = "Allow incoming database connections."

  ingress {
    from_port = 3306
    to_port = 3306
    protocol = "tcp"
    cidr_blocks = ["${var.vpc_cidr}"]
  }
  ingress {
    from_port = -1
    to_port = -1
    protocol = "icmp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port = 80
    to_port = 80
    protocol = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  egress {
    from_port = 443
    to_port = 443
    protocol = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  vpc_id = "${aws_vpc.default.id}"

  tags {
    Name = "DBServerSG"
  }
}

resource "aws_db_subnet_group" "iris_db" {
  name = "main"
  description = "Our main group of DB subnets"
  subnet_ids = [
    "${aws_subnet.us-west-2a-private.id}",
    "${aws_subnet.us-west-2b-private.id}",
    "${aws_subnet.us-west-2c-private.id}"
  ]
  tags {
    Name = "Iris MySQL DB subnet group"
  }
}



# RDS MySQL cluster

resource "aws_rds_cluster" "rds_iris" {
  depends_on = ["aws_db_subnet_group.iris_db"]
  count = "${var.use_aws_rds_cluster ? 1 : 0}"
  cluster_identifier = "aurora-cluster-iris"
  availability_zones = ["us-west-2a", "us-west-2b", "us-west-2c"]
  database_name = "iris"
  master_username = "foo"
  master_password = "foobar123"
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  vpc_security_group_ids = ["${aws_security_group.db.id}"]
  db_subnet_group_name = "${aws_db_subnet_group.iris_db.id}"
  final_snapshot_identifier = "iris-mysql"
  skip_final_snapshot = true
}

resource "aws_rds_cluster_instance" "rds_cluster_instances" {
  count = "${var.use_aws_rds_cluster ? 2 : 0}"
  identifier = "aurora-cluster-iris-${count.index}"
  cluster_identifier = "${aws_rds_cluster.rds_iris.id}"
  instance_class = "db.t2.small"
  publicly_accessible = false
}

output "rds_cluster_endpoint" {
  value = "${aws_rds_cluster.rds_iris.endpoint}"
}


# RDS MySQL instance

resource "aws_db_instance" "mysql_iris" {
  depends_on = ["aws_db_subnet_group.iris_db"]
  count = "${var.use_aws_rds_cluster ? 0 : 1}"
  allocated_storage    = 5
  storage_type         = "standard"
  engine               = "mysql"
  engine_version       = "5.7.16"
  instance_class       = "db.t2.micro"
  name                 = "iris"
  username             = "iris"
  password             = "foobar123"
  db_subnet_group_name = "${aws_db_subnet_group.iris_db.id}"
  final_snapshot_identifier = "iris-mysql"
  vpc_security_group_ids = ["${aws_security_group.db.id}"]
  skip_final_snapshot = true
}

output "rds_mysql_address" {
  value = "${aws_db_instance.mysql_iris.address}"
}

