resource "kubernetes_deployment" "hello-deployment" {
  metadata {
    name      = "hello-deployment"
    namespace = "default"
    labels = {
      app = "hello"
    }
  }

  spec {
    replicas = 3

    selector {
      match_labels = {
        app = "hello"
      }
    }

    template {
      metadata {
        labels = {
          app = "hello"
        }
      }

      spec {
        security_context {
          fs_group = 1337
        }
        container {
          image = "docker.io/waip/simple-http:v1.0.1"
          name  = "hello"

          port {
            container_port = 8000
          }
        }
      }
    }
  }

  depends_on = [
    module.autoneg
  ]
}

