file_content:
data "google_client_config" "default" {}


provider "kubernetes" {
  host                   = "https://${google_container_cluster.ltf_autopilot_cluster.endpoint}"
  token                  = data.google_client_config.default.access_token
  cluster_ca_certificate = base64decode(google_container_cluster.ltf_autopilot_cluster.master_auth[0].cluster_ca_certificate)

  # ignore_annotations = [
  #   "^autopilot\\.gke\\.io\\/.*",
  #   "^cloud\\.google\\.com\\/.*"
  # ]
}

locals {
  resource_prefix = lower(replace(var.deployment_id, "/[^a-z0-9\\-]+/", ""))
  user_class_map = {
    "http" = "HttpVectorSearchUser"
    "grpc" = "GrpcVectorSearchUser"
  }

  user_class = local.user_class_map[var.locust_test_type]
}

resource "google_project_iam_binding" "aiplatform_viewer_binding" {
  project = var.project_id
  role    = "roles/aiplatform.viewer"
  members = [
    "serviceAccount:${google_service_account.service_account.email}",
  ]
}

resource "google_project_iam_member" "aiplatform_viewer_k8s_binding" {
  project = var.project_id
  role    = "roles/aiplatform.viewer"
  member  = "serviceAccount:${var.project_id}.svc.id.goog[default/default]" # Standard format

  depends_on = [
    google_container_cluster.ltf_autopilot_cluster
  ]
}

# Create a Kubernetes namespace specific to this deployment to avoid Workload Identity conflicts
resource "kubernetes_namespace" "locust_namespace" {
  metadata {
    name = "${local.resource_prefix}-ns"
  }

  depends_on = [
    google_container_cluster.ltf_autopilot_cluster
  ]
}

# Create a dedicated Kubernetes service account for this deployment
resource "kubernetes_service_account" "locust_service_account" {
  metadata {
    name      = "${local.resource_prefix}-sa"
    namespace = kubernetes_namespace.locust_namespace.metadata[0].name

    # Add annotation for Workload Identity
    annotations = {
      "iam.gke.io/gcp-service-account" = google_service_account.service_account.email
    }
  }

  depends_on = [
    kubernetes_namespace.locust_namespace
  ]
}

resource "kubernetes_config_map" "locust_config" {
  metadata {
    name      = "${local.resource_prefix}-config"
    namespace = kubernetes_namespace.locust_namespace.metadata[0].name
  }

  data = {
    "locust_config.env" = file("${path.module}/../../../config/locust_config.env")
  }

  depends_on = [
    kubernetes_namespace.locust_namespace
  ]
}

resource "kubernetes_deployment" "locust_master" {
  metadata {
    name      = "${local.resource_prefix}-master"
    namespace = kubernetes_namespace.locust_namespace.metadata[0].name
  }
  spec {
    selector {
      match_labels = {
        app = "${local.resource_prefix}-master"
      }
    }
    template {
      metadata {
        labels = {
          app = "${local.resource_prefix}-master"
        }
      }
      spec {
        service_account_name            = kubernetes_service_account.locust_service_account.metadata[0].name
        automount_service_account_token = true

        volume {
          name = "${local.resource_prefix}-config"
          config_map {
            name         = kubernetes_config_map.locust_config.metadata[0].name
            default_mode = "0644"
          }
        }
        container {
          image = var.image
          name  = "locust-master"
          volume_mount {
            name       = "${local.resource_prefix}-config"
            mount_path = "/tasks/locust_config.env"
            sub_path   = "locust_config.env"
          }
          args = ["-f", "/tasks/locust.py", "--master", "--class-picker", "--tags=${var.locust_test_type}", "${local.user_class}"]
          port {
            container_port = 8089
            name           = "loc-master-web"
          }
          port {
            container_port = 5557
            name           = "loc-master-p1"
          }
          port {
            container_port = 5558
            name           = "loc-master-p2"
          }
        }
      }
    }
  }

  depends_on = [
    kubernetes_service_account.locust_service_account
  ]
}

resource "kubernetes_deployment" "locust_worker" {
  metadata {
    name      = "${local.resource_prefix}-worker"
    namespace = kubernetes_namespace.locust_namespace.metadata[0].name
  }
  spec {
    selector {
      match_labels = {
        app = "${local.resource_prefix}-worker"
      }
    }
    template {
      metadata {
        labels = {
          app = "${local.resource_prefix}-worker"
        }
      }
      spec {
        service_account_name            = kubernetes_service_account.locust_service_account.metadata[0].name
        automount_service_account_token = true

        volume {
          name = "${local.resource_prefix}-config"
          config_map {
            name         = kubernetes_config_map.locust_config.metadata[0].name
            default_mode = "0644"
          }
        }
        container {
          image = var.image
          name  = "locust-worker"
          volume_mount {
            name       = "${local.resource_prefix}-config"
            mount_path = "/tasks/locust_config.env"
            sub_path   = "locust_config.env"
          }
          args = ["-f", "/tasks/locust.py", "--worker", "--master-host", "${local.resource_prefix}-master", "--tags=${var.locust_test_type}", "${local.user_class}"]
          resources {
            requests = {
              cpu = "1000m"
            }
          }
        }
      }
    }
  }

  depends_on = [
    kubernetes_service_account.locust_service_account
  ]
}

resource "kubernetes_service" "locust_master" {
  metadata {
    name      = "${local.resource_prefix}-master"
    namespace = kubernetes_namespace.locust_namespace.metadata[0].name
    labels = {
      app = "${local.resource_prefix}-master"
    }
  }
  spec {
    selector = {
      app = "${local.resource_prefix}-master"
    }
    port {
      port        = 8089
      target_port = "loc-master-web"
      name        = "loc-master-web"
    }
    port {
      port        = 5557
      target_port = "loc-master-p1"
      name        = "loc-master-p1"
    }
    port {
      port        = 5558
      target_port = "loc-master-p2"
      name        = "loc-master-p2"
    }
  }
}

resource "kubernetes_service" "locust_master_web" {
  metadata {
    name      = "${local.resource_prefix}-master-web"
    namespace = kubernetes_namespace.locust_namespace.metadata[0].name
    annotations = var.create_external_ip ? {} : {
      "networking.gke.io/load-balancer-type" = "Internal"
    }
    labels = {
      app = "${local.resource_prefix}-master"
    }
  }
  spec {
    selector = {
      app = "${local.resource_prefix}-master"
    }
    port {
      port        = 8089
      target_port = "loc-master-web"
      name        = "loc-master-web"
    }
    type = "LoadBalancer"
  }
}

resource "kubernetes_horizontal_pod_autoscaler" "locust_worker_autoscaler" {
  metadata {
    name      = "${local.resource_prefix}-worker-autoscaler"
    namespace = kubernetes_namespace.locust_namespace.metadata[0].name
  }

  spec {
    min_replicas = var.min_replicas_worker
    max_replicas = 1000

    scale_target_ref {
      api_version = "apps/v1"
      kind        = "Deployment"
      name        = "${local.resource_prefix}-worker"
    }
    target_cpu_utilization_percentage = 50
  }
}

impacted_block_content:
resource "libvirt_pool" "cluster" {
  name = "${var.name}-storage-pool"
  type = "dir"
  path = "/var/lib/libvirt/images"
}

file_content:
terraform {
  required_providers {
    libvirt = {
      source  = "dmacvicar/libvirt"
      version = "0.8.3"
    }
    docker = {
      source  = "kreuzwerker/docker"
      version = "3.6.2"
    }
    random = {
      source  = "hashicorp/random"
      version = "3.7.2"
    }
  }
}

provider "libvirt" {
  uri = var.libvirt_uri
}

provider "docker" {
  host = "unix:///var/run/docker.sock"
}

locals {
  cidr_vpc_subnet_nodes          = "10.42.0.0/22"
  cidr_vpc_subnet_control_planes = "10.42.1.0/24"
  cidr_vpc_subnet_worker         = "10.42.2.0/24"
  revision                       = 1
}

# A way to force replacement of resources if the provider does not want to replace them
# see: https://developer.hashicorp.com/terraform/language/resources/terraform-data#example-usage-data-for-replace_triggered_by
resource "terraform_data" "replacement" {
  input = local.revision
}

resource "random_password" "init_secret" {
  length           = 32
  special          = true
  override_special = "_%@"
}

resource "docker_image" "qemu_metadata" {
  name         = var.metadata_api_image
  keep_locally = true
}

resource "docker_container" "qemu_metadata" {
  name         = "${var.name}-qemu-metadata"
  image        = docker_image.qemu_metadata.image_id
  network_mode = "host"
  rm           = true
  command = [
    "--network",
    "${var.name}-network",
    "--libvirt-uri",
    "${var.metadata_libvirt_uri}",
    "--initsecrethash",
    "${random_password.init_secret.bcrypt_hash}",
  ]
  mounts {
    source = abspath(var.libvirt_socket_path)
    target = "/var/run/libvirt/libvirt-sock"
    type   = "bind"
  }
}

module "node_group" {
  source           = "./modules/instance_group"
  base_name        = var.name
  for_each         = var.node_groups
  node_group_name  = each.key
  role             = each.value.role
  amount           = each.value.initial_count
  state_disk_size  = each.value.disk_size
  vcpus            = each.value.vcpus
  memory           = each.value.memory
  machine          = var.machine
  cidr             = each.value.role == "control-plane" ? local.cidr_vpc_subnet_control_planes : local.cidr_vpc_subnet_worker
  network_id       = libvirt_network.constellation.id
  pool             = libvirt_pool.cluster.name
  boot_mode        = var.constellation_boot_mode
  boot_volume_id   = libvirt_volume.image_id.id
  kernel_volume_id = local.kernel_volume_id
  initrd_volume_id = local.initrd_volume_id
  kernel_cmdline   = each.value.role == "control-plane" ? local.kernel_cmdline : var.constellation_cmdline
  firmware         = var.firmware
  nvram            = var.nvram
}

resource "libvirt_pool" "cluster" {
  name = "${var.name}-storage-pool"
  type = "dir"
  path = "/var/lib/libvirt/images"
}

resource "libvirt_volume" "image_id" {
  name   = "${var.name}-node-image"
  pool   = libvirt_pool.cluster.name
  source = var.image_id
  format = var.image_format
}

resource "libvirt_volume" "constellation_kernel" {
  name   = "${var.name}-kernel"
  pool   = libvirt_pool.cluster.name
  source = var.constellation_kernel
  format = "raw"
  count  = var.constellation_boot_mode == "direct-linux-boot" ? 1 : 0
}

resource "libvirt_volume" "constellation_initrd" {
  name   = "${var.name}-initrd"
  pool   = libvirt_pool.cluster.name
  source = var.constellation_initrd
  format = "raw"
  count  = var.constellation_boot_mode == "direct-linux-boot" ? 1 : 0
}

resource "libvirt_network" "constellation" {
  name      = "${var.name}-network"
  mode      = "nat"
  addresses = ["10.42.0.0/16"]
  dhcp {
    enabled = true
  }
  dns {
    enabled = true
  }
}

locals {
  kernel_volume_id = var.constellation_boot_mode == "direct-linux-boot" ? libvirt_volume.constellation_kernel[0].id : null
  initrd_volume_id = var.constellation_boot_mode == "direct-linux-boot" ? libvirt_volume.constellation_initrd[0].id : null
  kernel_cmdline   = var.constellation_boot_mode == "direct-linux-boot" ? var.constellation_cmdline : null
}

impacted_block_content:
resource "local_file" "python_file" {
  filename          = "${path.cwd}/../../test.py"
  sensitive_content = "def test (event, context):\n\tprint ('This is a test for integration testing to check creation of a lambda function')"
}

file_content:
variable "resource_name" {
  type        = string
  default     = "turbot-test-20200125-create-update"
  description = "Name of the resource used throughout the test."
}

variable "aws_profile" {
  type        = string
  default     = "default"
  description = "AWS credentials profile used for the test. Default is to use the default profile."
}

variable "aws_region" {
  type        = string
  default     = "us-east-1"
  description = "AWS region used for the test. Does not work with default region in config, so must be defined here."
}

variable "aws_region_alternate" {
  type        = string
  default     = "us-east-2"
  description = "Alternate AWS region used for tests that require two regions (e.g. DynamoDB global tables)."
}

provider "aws" {
  profile = var.aws_profile
  region  = var.aws_region
}

provider "aws" {
  alias   = "alternate"
  profile = var.aws_profile
  region  = var.aws_region_alternate
}

data "aws_partition" "current" {}
data "aws_caller_identity" "current" {}
data "aws_region" "primary" {}
data "aws_region" "alternate" {
  provider = aws.alternate
}

data "null_data_source" "resource" {
  inputs = {
    scope = "arn:${data.aws_partition.current.partition}:::${data.aws_caller_identity.current.account_id}"
  }
}

# Create AWS > Lambda > Function
resource "local_file" "python_file" {
  filename          = "${path.cwd}/../../test.py"
  sensitive_content = "def test (event, context):\n\tprint ('This is a test for integration testing to check creation of a lambda function')"
}

data "archive_file" "zip" {
  depends_on  = [local_file.python_file]
  type        = "zip"
  source_file = "${path.cwd}/../../test.py"
  output_path = "${path.cwd}/../../test.zip"
}

resource "aws_iam_role" "aws_lambda_function" {
  name = var.resource_name
  assume_role_policy = jsonencode({
    "Version" : "2012-10-17",
    "Statement" : [
      {
        "Action" : "sts:AssumeRole",
        "Principal" : {
          "Service" : "lambda.amazonaws.com"
        },
        "Effect" : "Allow",
        "Sid" : ""
      }
    ]
  })
}

resource "aws_lambda_function" "named_test_resource" {
  function_name                  = var.resource_name
  role                           = aws_iam_role.aws_lambda_function.arn
  handler                        = "test.test"
  runtime                        = "python3.11"
  filename                       = "${path.cwd}/../../test.zip"
  reserved_concurrent_executions = 2
  tags = {
    name = var.resource_name
  }
}

resource "aws_sns_topic" "default" {
  name = "call-lambda-maybe"
}

resource "aws_lambda_permission" "with_sns" {
  statement_id  = "AllowExecutionFromSNS"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.named_test_resource.function_name
  principal     = "sns.amazonaws.com"
  source_arn    = aws_sns_topic.default.arn
}

output "resource_aka" {
  value = aws_lambda_function.named_test_resource.arn
}

output "sns_arn" {
  value = aws_sns_topic.default.arn
}

output "account_id" {
  value = data.aws_caller_identity.current.account_id
}

output "aws_partition" {
  value = data.aws_partition.current.partition
}

output "region_name" {
  value = data.aws_region.primary.name
}

output "resource_name" {
  value = var.resource_name
}

provider "metal" {
  auth_token = var.auth_token
}

locals {
  ssh_key_name = "metal-key"
}

resource "random_id" "cloud" {
  byte_length = 8
}

resource "tls_private_key" "ssh_key_pair" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

resource "local_file" "cluster_private_key_pem" {
  content         = chomp(tls_private_key.ssh_key_pair.private_key_pem)
  filename        = pathexpand(format("%s", local.ssh_key_name))
  file_permission = "0600"
}

resource "local_file" "cluster_public_key" {
  content         = chomp(tls_private_key.ssh_key_pair.public_key_openssh)
  filename        = pathexpand(format("%s.pub", local.ssh_key_name))
  file_permission = "0600"
}

resource "metal_ssh_key" "kubernetes-on-metal" {
  name       = format("terraform-k8s-%s", random_id.cloud.b64_url)
  public_key = chomp(tls_private_key.ssh_key_pair.public_key_openssh)
}

resource "metal_reserved_ip_block" "api_server" {
  project_id = var.project_id
  # facility   = var.facility != "" ? var.facility : null
  metro      = var.metro
  quantity   = 1
  tags             = ["kubernetes", "control-plane-${var.cluster_name}", "kube-apiserver"]
}

resource "kubernetes_namespace" "bootstrap" {
  metadata {
    name = "bootstrap"
    labels = {
      "app.kubernetes.io/managed-by" = "plural"
      "app.plural.sh/name" = var.namespace
    }
  }
  depends_on = [
    rke_cluster.cluster
  ]
}

