  depends_on = [module.base_instance]
  provisioner "file" {
    source = var.ssh_public_key
    destination = "/tmp/id_rsa.pub"
    connection {
      type = "ssh"
      user = var.remote_user
      agent = false
      host = module.base_instance.instance_XXXX_ip
      timeout = "15m"
      private_key = file(var.ssh_private_key)
    }
