resource "oci_core_instance_console_connection" "test_instance_cnx" {
  depends_on = [oci_core_instance.test_instance]
  #Required
  instance_id = oci_core_instance.test_instance.id
  public_key  = file(var.ssh_public_key_path)
}

file_content:
// Copyright (c) 2021 Oracle and/or its affiliates. All rights reserved.
// Licensed under the Universal Permissive License v 1.0 as shown
// at http://oss.oracle.com/licenses/upl.
terraform {
  required_providers {
    oci = ">= 3.56.0"
  }
}

variable "tenancy_ocid" {}
variable "user_ocid" {}
variable "fingerprint" {}
variable "private_key_path" {}
variable "region" {}
variable "compartment_id" {}
variable "availability_domain_id" {}
variable "subnet_id" {}
variable "instance_shape" {}
variable "instance_image_ocid" {}

variable "ssh_private_key_path" {}
variable "ssh_authorized_key_path" {}
variable "ssh_user" {}

variable "oci_utils_rpms_dir" {}


variable "dns_search_domains" {}
variable "dns_server_ip" {}
variable "http_proxy_url" {}
variable "https_proxy_url" {}

variable "subnet_identifier" {
  type = map(string)
  default = {
    us-ashburn-1 = "",
    uk-london-1  = ""
  }
}


provider "oci" {
  tenancy_ocid     = var.tenancy_ocid
  user_ocid        = var.user_ocid
  fingerprint      = var.fingerprint
  private_key_path = var.private_key_path
  region           = var.region
}

data "template_file" "resolver_config" {
  template = file(join("/", [abspath(path.root), "userdata", "oci_resolver_config"]))
  vars = {
    dns_search_domains = var.dns_search_domains
    dns_server_ip      = var.dns_server_ip
  }
}
data "template_file" "tests_environement" {
  template = file(join("/", [abspath(path.root), "userdata", "oci-tests-env"]))
  vars = {
    http_proxy_url  = var.http_proxy_url
    https_proxy_url = var.https_proxy_url
  }
}

resource "oci_core_instance" "test_instance" {
  availability_domain = var.availability_domain_id
  compartment_id      = var.compartment_id
  display_name        = "OCIUtilsTestInstance"
  shape               = var.instance_shape

  create_vnic_details {
    subnet_id        = var.subnet_id
    display_name     = "Primaryvnic"
    assign_public_ip = false
  }

  source_details {
    source_type = "image"
    source_id   = var.instance_image_ocid
  }

  preserve_boot_volume = false

  metadata = {
    ssh_authorized_keys = file(var.ssh_authorized_key_path)
  }


  timeouts {
    create = "60m"
  }

}

resource "oci_core_vnic_attachment" "test_vnic_attachment_nic0" {
  count = 2
  create_vnic_details {
    subnet_id        = var.subnet_id
    assign_public_ip = false
  }

  instance_id = oci_core_instance.test_instance.id
  nic_index   = 0
}


resource "oci_core_vnic_attachment" "test_vnic_attachment_nic1" {
  count = 2
  create_vnic_details {
    subnet_id        = var.subnet_id
    assign_public_ip = false
  }
  instance_id = oci_core_instance.test_instance.id
  nic_index   = 1
}

resource "oci_core_volume" "test_volume" {
  availability_domain = var.availability_domain_id
  compartment_id      = var.compartment_id
  display_name        = "OCIUtilsTestVolume"
  size_in_gbs         = 128
}
resource "oci_core_volume_attachment" "test_volume_attachment" {
  #Required
  attachment_type = "iscsi"
  instance_id     = oci_core_instance.test_instance.id
  volume_id       = oci_core_volume.test_volume.id

  is_read_only = false

}

resource "oci_core_instance_console_connection" "test_instance_cnx" {
  depends_on = [oci_core_instance.test_instance]
  #Required
  instance_id = oci_core_instance.test_instance.id
  public_key  = file(var.ssh_public_key_path)
}
output "instance_private_ip" {
  value = oci_core_instance.test_instance.private_ip
}


resource "null_resource" "deploy_test" {
  depends_on = [oci_core_instance.test_instance]

  provisioner "file" {
    source      = join("/", [var.oci_utils_rpms_dir, "/"])
    destination = "/tmp"

    connection {
      type        = "ssh"
      agent       = false
      user        = var.ssh_user
      host        = oci_core_instance.test_instance.private_ip
      timeout     = "15m"
      private_key = file(var.ssh_private_key_path)
    }

  }

  provisioner "file" {
    content     = data.template_file.resolver_config.rendered
    destination = "/tmp/resolv.conf"

    connection {
      type        = "ssh"
      agent       = false
      user        = var.ssh_user
      host        = oci_core_instance.test_instance.private_ip
      timeout     = "15m"
      private_key = file(var.ssh_private_key_path)
    }

  }
  provisioner "file" {
    content     = data.template_file.tests_environement.rendered
    destination = "/tmp/oci-tests-env.sh"

    connection {
      type        = "ssh"
      agent       = false
      user        = var.ssh_user
      host        = oci_core_instance.test_instance.private_ip
      timeout     = "15m"
      private_key = file(var.ssh_private_key_path)
    }
  }

  // do this right now as other command may need it
  provisioner "remote-exec" {
    connection {
      type        = "ssh"
      agent       = false
      user        = var.ssh_user
      host        = oci_core_instance.test_instance.private_ip
      timeout     = "15m"
      private_key = file(var.ssh_private_key_path)
    }
    inline = [
      "/bin/sudo /bin/cp --force /tmp/oci-tests-env.sh /etc/profile.d",
      "/bin/sudo /bin/cp --force /etc/resolv.conf /etc/resolv.conf.back",
      "/bin/sudo /bin/cp --force /tmp/resolv.conf /etc/resolv.conf",
    ]
  }

  provisioner "remote-exec" {
    connection {
      type        = "ssh"
      agent       = false
      user        = var.ssh_user
      host        = oci_core_instance.test_instance.private_ip
      timeout     = "15m"
      private_key = file(var.ssh_private_key_path)
    }

    inline = [
      "/bin/sudo --login /usr/bin/yum install --quiet --assumeyes gcc",
      "/bin/sudo --login /usr/bin/pip3 install --quiet --upgrade pip",
      "/bin/sudo --login /usr/bin/pip3 install setuptools --upgrade",
      "/bin/sudo --login /usr/bin/yum localinstall --assumeyes /tmp/oci-utils-*.rpm",
      "/bin/sudo --login /usr/bin/systemctl enable --now ocid",
      "/bin/sudo --login /usr/bin/systemctl enable --now libvirtd",
      "/bin/sudo --login /usr/bin/pip3 install wheel"

    ]
  }

}

resource "null_resource" "deploy_iso" {
  depends_on = [null_resource.deploy_test]

  provisioner "remote-exec" {
    connection {
      type        = "ssh"
      agent       = false
      user        = var.ssh_user
      host        = oci_core_instance.test_instance.private_ip
      timeout     = "15m"
      private_key = file(var.ssh_private_key_path)
    }
    inline = [
      "wget -O /var/tmp/OracleLinux-R7-U9-Server-x86_64-dvd.iso --no-directories --progress=bar https://ca-artifacts.us.oracle.com/ISOs/build-isos/x86_64-el7-u9-isos/LATEST/OracleLinux-R7-U9-Server-x86_64-dvd.iso"
    ]
  }
}

resource "null_resource" "run_test" {
  depends_on = [null_resource.deploy_iso]

  provisioner "remote-exec" {
    connection {
      type        = "ssh"
      agent       = false
      user        = var.ssh_user
      host        = oci_core_instance.test_instance.private_ip
      timeout     = "15m"
      private_key = file(var.ssh_private_key_path)
    }
    // do not use --login as it make the shell to change dir
    inline = [
      "cd /opt/oci-utils/ && /bin/sudo --preserve-env /bin/python3 /opt/oci-utils/setup.py oci_tests --tests-base=/opt/oci-utils/tests/data"
    ]
  }


}

variable "tenancy_ocid" {}
variable "compartment_ocid" {}
variable "oracle_region" {}
variable "environment" {}
variable "vcn_cidr" {}
variable "public_subnet_cidr" {}
variable "jvb_subnet_cidr" {}
variable "vcn_name" {}
variable "vcn_dns_label" {}
variable "resource_name_root" {}

provider "oci" {
  region = var.oracle_region
  tenancy_ocid = var.tenancy_ocid
}

terraform {
  backend "s3" {
    skip_region_validation = true
    skip_credentials_validation = true
    skip_metadata_api_check = true
    force_path_style = true
  }
  required_providers {
      oci = {
          source  = "oracle/oci"
      }
  }
}

// ============ VCN ============

resource "oci_core_vcn" "vcn" {
  cidr_block     = var.vcn_cidr
  compartment_id = var.compartment_ocid
  display_name   = var.vcn_name
  dns_label      = var.vcn_dns_label
}


resource "oci_core_internet_gateway" "internet_gateway" {
  compartment_id = var.compartment_ocid
  display_name   = "Internet Gateway ${oci_core_vcn.vcn.display_name}"
  vcn_id         = oci_core_vcn.vcn.id
}

data "oci_core_services" "object_storage_services" {
  filter {
    name   = "name"
    values = ["OCI .* Object Storage"]
    regex  = true
  }
}

data "oci_core_services" "all_services" {
  filter {
    name   = "name"
    values = ["All .* Services In Oracle Services Network"]
    regex  = true
  }
}

resource "oci_core_service_gateway" "service_gateway" {
  compartment_id = var.compartment_ocid
  vcn_id = oci_core_vcn.vcn.id
  display_name   = "Service Gateway ${oci_core_vcn.vcn.display_name}"

  services {
    service_id = lookup(data.oci_core_services.all_services.services[0], "id")
  }
}

resource "oci_core_route_table" "route_table" {
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.vcn.id
  display_name   = "Route Table ${oci_core_vcn.vcn.display_name}"

  route_rules {
    destination       = "0.0.0.0/0"
    destination_type  = "CIDR_BLOCK"
    network_entity_id = oci_core_internet_gateway.internet_gateway.id
  }

  route_rules {
    destination       = lookup(data.oci_core_services.object_storage_services.services[0], "cidr_block")
    destination_type  = "SERVICE_CIDR_BLOCK"
    network_entity_id = oci_core_service_gateway.service_gateway.id
  }
}

// ============ NETWORKS SECURITY GROUPS ============

resource "oci_core_network_security_group" "public_network_security_group" {
    compartment_id = var.compartment_ocid
    vcn_id         = oci_core_vcn.vcn.id
    display_name   = "${var.resource_name_root}-PublicSecurityGroup"
}

resource "oci_core_network_security_group_security_rule" "public_network_security_group_security_rule_1" {
    network_security_group_id = oci_core_network_security_group.public_network_security_group.id
    direction                 = "EGRESS"
    destination               = "0.0.0.0/0"
    protocol                  = "all"
}

resource "oci_core_network_security_group_security_rule" "public_network_security_group_security_rule_2" {
    network_security_group_id = oci_core_network_security_group.public_network_security_group.id
    protocol                  = "6"   //tcp
    direction                 = "INGRESS"
    source                    = "0.0.0.0/0"
    stateless                 = false

    tcp_options {
        destination_port_range {
          min = 22
          max = 22
        }
    }
}

resource "oci_core_network_security_group" "jvb_network_security_group" {
    compartment_id = var.compartment_ocid
    vcn_id         = oci_core_vcn.vcn.id
    display_name   = "${var.resource_name_root}-JVBSecurityGroup"
}

resource "oci_core_network_security_group_security_rule" "jvb_network_security_group_security_rule_1" {
    network_security_group_id = oci_core_network_security_group.jvb_network_security_group.id
    direction                 = "EGRESS"
    destination               = "0.0.0.0/0"
    protocol                  = "all"
}

resource "oci_core_network_security_group_security_rule" "jvb_network_security_group_security_rule_2" {
    network_security_group_id = oci_core_network_security_group.jvb_network_security_group.id
    protocol                  = "6"   //tcp
    direction                 = "INGRESS"
    source                    = var.vcn_cidr
    stateless                 = false

    tcp_options {
        destination_port_range {
          min = 22
          max = 22
        }
    }
}

resource "oci_core_network_security_group_security_rule" "jvb_network_security_group_security_rule_3" {
    network_security_group_id = oci_core_network_security_group.jvb_network_security_group.id
    protocol                  = "6"   //tcp
    direction                 = "INGRESS"
    source                    = "0.0.0.0/0"
    stateless                 = false

    tcp_options {
        destination_port_range {
          min = 443
          max = 443
        }
    }
}

resource "oci_core_network_security_group_security_rule" "jvb_network_security_group_security_rule_4" {
    network_security_group_id = oci_core_network_security_group.jvb_network_security_group.id
    protocol                  = "17"   //udp
    direction                 = "INGRESS"
    source                    = "0.0.0.0/0"
    stateless                 = false

    udp_options {
        destination_port_range {
          min = 10000
          max = 10000
        }
    }
}



// ============ SUBNETS ============

resource "oci_core_subnet" "public_subnet" {
  depends_on          = [oci_core_network_security_group.public_network_security_group, oci_core_security_list.private_security_list]
  cidr_block          = var.public_subnet_cidr
  display_name        = "${var.resource_name_root}-PublicSubnet1"
  dns_label           = "pubsubnet1"
  compartment_id      = var.compartment_ocid
  vcn_id              = oci_core_vcn.vcn.id
  security_list_ids   = ["${oci_core_security_list.private_security_list.id}"]
  route_table_id      = oci_core_route_table.route_table.id
}

resource "oci_core_subnet" "jvb_subnet" {
  depends_on          = [oci_core_network_security_group.jvb_network_security_group, oci_core_security_list.private_security_list]
  cidr_block          = var.jvb_subnet_cidr
  display_name        = "${var.resource_name_root}-JVBSubnet64"
  dns_label           = "jvbsubnet64"
  compartment_id      = var.compartment_ocid
  vcn_id              = oci_core_vcn.vcn.id
  security_list_ids   = ["${oci_core_security_list.private_security_list.id}"]
  route_table_id      = oci_core_route_table.route_table.id
}

// ============ OUTPUTS ============

output "vcn_name" {
  value = oci_core_vcn.vcn.display_name
}

output "route_table_name" {
  value = oci_core_route_table.route_table.display_name
}

output "internet_gateway_name" {
  value = oci_core_internet_gateway.internet_gateway.display_name
}

output "private_security_list_name" {
  value = oci_core_security_list.private_security_list.display_name
}

output "public_network_security_group_name" {
  value = oci_core_network_security_group.public_network_security_group.display_name
}

output "jvb_network_security_group_name" {
  value = oci_core_network_security_group.jvb_network_security_group.display_name
}

output "public_subnet_name" {
  value = oci_core_subnet.public_subnet.display_name
}

output "jvb_subnet_name" {
  value = oci_core_subnet.jvb_subnet.display_name
}

# Copyright (c) 2024 Oracle Corporation and/or affiliates.  All rights reserved.
# Licensed under the Universal Permissive License v 1.0 as shown at https://oss.oracle.com/licenses/upl

resource "oci_load_balancer_load_balancer" "lb" {
  count          = var.create_load_balancer ? 1 : 0
  compartment_id = var.compartment_id
  display_name   = "${var.prefix}-load-balancer"
  shape          = lookup(var.load_balancer_shape, "shape")
  subnet_ids     = [var.subnet_id]
  is_private     = "true"

  # Optional
  shape_details {
    minimum_bandwidth_in_mbps = lookup(var.load_balancer_shape, "flex_min")
    maximum_bandwidth_in_mbps = lookup(var.load_balancer_shape, "flex_max")
  }
  freeform_tags = var.freeform_tags
}

resource "oci_load_balancer_backend_set" "lb_backend" {
  health_checker {
    protocol = var.load_balancer_protocol
    port     = var.load_balancer_port
    url_path = "/sys/health"
  }

  load_balancer_id = local.lb_ocid
  name             = "${var.prefix}-lb-backend"
  policy           = var.load_balancer_policy
}

resource "oci_core_instance_configuration" "instance_config" {
  compartment_id = var.compartment_id
  display_name   = "${var.prefix}-instance-configuration"
  freeform_tags  = var.freeform_tags

  instance_details {
    instance_type = "compute"

    launch_details {
      availability_domain = var.availability_domain_id
      compartment_id      = var.compartment_id
      display_name        = "${var.prefix}-compute"
      shape               = lookup(var.instance_shape, "shape", "VM.Standard2.2")

      dynamic "shape_config" {
        for_each = length(regexall("Flex", lookup(var.instance_shape, "shape", "VM.Standard.E3.Flex"))) > 0 ? [1] : []
        content {
          ocpus         = max(1, lookup(var.instance_shape, "ocpus", 1))
          memory_in_gbs = (lookup(var.instance_shape, "memory", 4) / lookup(var.instance_shape, "ocpus", 1)) > 64 ? (lookup(var.instance_shape, "ocpus", 1) * 16) : lookup(var.instance_shape, "memory", 4)
        }
      }

      source_details {
        source_type             = "image"
        image_id                = var.image_ocid
        boot_volume_size_in_gbs = lookup(var.instance_shape, "boot_volume_size", null)
      }

      metadata = {
        ssh_authorized_keys = file(var.ssh_public_key_path)
        user_data           = var.instance_user_data
      }

      create_vnic_details {
        assign_public_ip = "false"
        subnet_id        = var.subnet_id
      }
    }
  }
}

resource "oci_core_instance_pool" "instance_pool" {
  depends_on                = [oci_load_balancer_backend_set.lb_backend]
  instance_configuration_id = oci_core_instance_configuration.instance_config.id
  compartment_id            = var.compartment_id
  display_name              = "${var.prefix}-instance-pool"
  size                      = var.pool_size
  freeform_tags             = var.freeform_tags

  placement_configurations {
    availability_domain = var.availability_domain_id
    primary_subnet_id   = var.subnet_id
  }

  load_balancers {
    backend_set_name = "${var.prefix}-lb-backend"
    load_balancer_id = local.lb_ocid
    port             = var.load_balancer_port
    vnic_selection   = "PrimaryVnic"
  }
}

resource "oci_load_balancer_listener" "listener" {
  depends_on               = [oci_core_instance_pool.instance_pool, oci_load_balancer_backend_set.lb_backend]
  default_backend_set_name = oci_core_instance_pool.instance_pool.load_balancers[0].backend_set_name
  load_balancer_id         = local.lb_ocid
  name                     = "${var.prefix}-listener"
  port                     = var.load_balancer_port
  protocol                 = var.load_balancer_protocol
}

